}

export const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
  sampleRate: 44100,
  latencyHint: 'interactive'
});

let workletLoaded = false;

export async function loadProcessor() {
  if (workletLoaded) return true;

  const WORKLET_CODE = `
    /* =========================
       DSP UTILS
    ========================= */
    const clamp = (v, a, b) => Math.max(a, Math.min(b, v));

    /* =========================
       PITCH SMOOTHER (MEEND)
    ========================= */
    class PitchSmoother {
      constructor() { this.current = 220; }
      step(target) {
        // Sigmoid Neural Glide logic
        const diff = target - this.current;
        this.current += diff * 0.0022; 
        return this.current;
      }
    }

    /* =========================
       GLOTTAL PULSE (ROSENBERG)
    ========================= */
    class GlottalSource {
      constructor(sr) {
        this.sr = sr;
        this.phase = 0;
      }
      process(freq) {
        const T = this.sr / freq;
        this.phase++;
        if (this.phase >= T) this.phase = 0;

        const open = 0.4 * T;
        const close = 0.16 * T;

        if (this.phase < open) {
          const x = this.phase / open;
          return 0.5 * (1 - Math.cos(Math.PI * x));
        }
        if (this.phase < open + close) {
          const x = (this.phase - open) / close;
          return Math.cos(Math.PI * x);
        }
        return 0;
      }
    }

    /* =========================
       FORMANT FILTER BANK
    ========================= */
    class BandPass {
      constructor(sr) {
        this.sr = sr;
        this.y1 = this.y2 = 0;
      }
      set(f, bw) {
        const w = 2 * Math.PI * f / this.sr;
        const r = Math.exp(-Math.PI * bw / this.sr);
        this.a1 = 2 * r * Math.cos(w);
        this.a2 = -r * r;
        this.b0 = 1 - r;
      }
      process(x) {
        const y = this.b0 * x + this.a1 * this.y1 + this.a2 * this.y2;
        this.y2 = this.y1;
        this.y1 = y;
        return y;
      }
    }

    class FormantFilter {
      constructor(sr) {
        this.sr = sr;
        this.bands = Array.from({ length: 5 }, () => new BandPass(sr));
        this.vowelData = {
          aa: [700, 1220, 2600, 3500, 4500],
          ee: [300, 2200, 3000, 3600, 4200],
          oo: [400, 800, 2400, 3200, 4000]
        };
        this.setVowel("aa");
      }
      setVowel(v) {
        const freqs = this.vowelData[v] || this.vowelData.aa;
        freqs.forEach((f, i) => this.bands[i].set(f, 90 + i * 50));
      }
      process(x, gain = 1.0) {
        return this.bands.reduce((s, b) => s + b.process(x), 0) * 0.25 * gain;
      }
    }

    /* =========================
       VOCAL PROCESSOR
    ========================= */
    class VocalProcessor extends AudioWorkletProcessor {
      constructor() {
        super();
        this.pitch = new PitchSmoother();
        this.glottal = new GlottalSource(sampleRate);
        this.formant = new FormantFilter(sampleRate);

        this.state = {
          freq: 220,
          tonic: 220,
          ragaShruti: [0, 200, 400, 500, 700, 900, 1100],
          gamak: false,
          phoneme: "aa",
          bhakti: false,
          gender: "male"
        };

        this.time = 0;
        this.port.onmessage = e => Object.assign(this.state, e.data);
      }

      snapToRaga(freq) {
        const cents = 1200 * Math.log2(freq / this.state.tonic);
        let best = cents, min = 1e9;
        for (const s of this.state.ragaShruti) {
          const d = Math.abs(cents - s);
          if (d < min) { min = d; best = s; }
        }
        return this.state.tonic * Math.pow(2, best / 1200);
      }

      process(_, outputs) {
        const out = outputs[0][0];
        const { freq, gamak, phoneme, bhakti, gender } = this.state;

        for (let i = 0; i < out.length; i++) {
          let f = this.snapToRaga(freq);

          if (gamak) {
            f *= (1 + 0.015 * Math.sin(2 * Math.PI * 6.5 * this.time));
          }

          const targetFreq = this.pitch.step(f);
          let sig = this.glottal.process(targetFreq);

          this.formant.setVowel(phoneme === "ka" || phoneme === "ta" ? "aa" : phoneme);

          let fGain = bhakti ? 1.15 : 1.0;
          if (gender === "female") fGain *= 0.8; // brighter but smaller body

          sig = this.formant.process(sig, fGain);

          if (bhakti) {
            sig += (Math.random() * 2 - 1) * 0.04; // breath
            sig = Math.tanh(sig * 2.2);            // drive
          }

          out[i] = sig * 0.4;
          this.time += 1 / sampleRate;
        }
        return true;
      }
    }

    registerProcessor("vocal-processor", VocalProcessor);
  `;

  const blob = new Blob([WORKLET_CODE], { type: 'application/javascript' });
  const url = URL.createObjectURL(blob);

  try {
    await audioContext.audioWorklet.addModule(url);
    workletLoaded = true;
    return true;
  } catch (err) {
    console.error("Failed to load AudioWorklet", err);
    return false;
  }
}

export function createPluginNode() {
  return new AudioWorkletNode(audioContext, "vocal-processor");
}

import { GoogleGenAI, Type } from "@google/genai";
import { Raga, Style, Mood, Composition } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const compositionSchema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING },
    melody: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midi: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        },
        required: ["midi", "start", "duration", "velocity"]
      }
    },
    bass: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midi: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        }
      }
    },
    drums: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midiNote: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        }
      }
    },
    vocalTimeline: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          time: { type: Type.NUMBER },
          midi: { type: Type.NUMBER },
          phoneme: { type: Type.STRING },
          emotion: { type: Type.STRING },
          duration: { type: Type.NUMBER }
        }
      }
    },
    lyrics: { type: Type.STRING }
  },
  required: ["title", "melody", "vocalTimeline", "lyrics"]
};

export async function generateComposition(
  raga: Raga,
  style: Style,
  mood: Mood,
  bpm: number,
  lyricsSeed: string
): Promise<Composition> {
  const prompt = `
    Compose a 4-bar musical piece.
    Raga: ${raga}
    Style: ${style}
    Mood: ${mood}
    BPM: ${bpm}
    Lyrics Seed: ${lyricsSeed}

    If style is Wizard Rock: Use distorted electric guitar feel for melody, driving bass, and big arena drums.
    If style is Classical: Use Sitar feel, rhythmic drones, and Tabla patterns.

    For Vocal Timeline: 
    - Map syllables to notes.
    - Use phonemes like 'aa', 'ee', 'oo', 'ka', 'ta'.
    - Apply 'Bhakti' emotion for devotional style.
    - Ensure Pakad (signature phrases) of ${raga} are followed.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: compositionSchema
    }
  });

  const data = JSON.parse(response.text);

  return {
    ...data,
    id: crypto.randomUUID(),
    raga,
    style,
    mood,
    bpm,
    timestamp: Date.now()
  };
}

export async function generateLyrics(raga: Raga, style: Style, mood: Mood): Promise<string> {
  const prompt = `Generate a 2-line lyrical couplet for a song in Raag ${raga}. Style: ${style}, Mood: ${mood}. Output only the lyrics in Hindi/English transliteration.`;
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt
  });
  return response.text.trim();
}

import { Composition } from "../types";

const STORAGE_KEY = "ragamidi_compositions";

export function saveToLibrary(comp: Composition) {
  const existing = getLibrary();
  const updated = [comp, ...existing];
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
}

export function getLibrary(): Composition[] {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : [];
}

export function deleteFromLibrary(id: string) {
  const existing = getLibrary();
  const updated = existing.filter(c => c.id !== id);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
}

import { Composition } from "../types";

export function exportMidiFile(comp: Composition) {
  // Simple MIDI Binary Encoding (Minimal Implementation)
  const header = [
    0x4d, 0x54, 0x68, 0x64, // MThd
    0x00, 0x00, 0x00, 0x06, // Header length
    0x00, 0x01,             // Format 1
    0x00, 0x01,             // 1 Track (simplified)
    0x01, 0xe0              // 480 ticks per beat
  ];

  const trackHeader = [0x4d, 0x54, 0x72, 0x6b]; // MTrk

  let trackData: number[] = [];

  // Add Melody Notes
  comp.melody.forEach(note => {
    const ticks = Math.floor(note.start * 480);
    // Note On (Delta time 0 for simplicity in this proto)
    trackData.push(0x00, 0x90, note.midi, note.velocity);
    // Note Off (After duration)
    // In a real implementation, we would sort all events by time.
  });

  // For a robust MIDI export, we use a specialized library or more complex logic.
  // This is a placeholder for the binary structure.

  const blob = new Blob([new Uint8Array([...header, ...trackHeader, 0, 0, 0, trackData.length, ...trackData])], { type: "audio/midi" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${comp.title.replace(/\s+/g, '_')}.mid`;
  a.click();
}

import React, { useState, useEffect, useRef } from 'react';
import { Raga, Style, Mood, Composition, VocalParams } from './types';
import { loadProcessor, createPluginNode, audioContext } from './audioContext';
import { generateComposition, generateLyrics } from './services/geminiService';
import { saveToLibrary, getLibrary, deleteFromLibrary } from './services/storageService';
import { exportMidiFile } from './services/midiService';
import { RAGA_SCALES } from './constants';

export default function App() {
  const [activeComp, setActiveComp] = useState<Composition | null>(null);
  const [library, setLibrary] = useState<Composition[]>([]);
  const [raga, setRaga] = useState<Raga>(Raga.Yaman);
  const [style, setStyle] = useState<Style>(Style.Classical);
  const [mood, setMood] = useState<Mood>(Mood.Peaceful);
  const [lyricsSeed, setLyricsSeed] = useState("");
  const [vocalParams, setVocalParams] = useState<VocalParams>({
    vibrato: 0.5,
    grit: 0.1,
    ornamentation: "meend",
    timbre: "kishore",
    gender: "male"
  });
  const [isPlaying, setIsPlaying] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isReady, setIsReady] = useState(false);

  const workletNodeRef = useRef<AudioWorkletNode | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    setLibrary(getLibrary());
  }, []);

  const initEngine = async () => {
    const success = await loadProcessor();
    if (success) {
      const node = createPluginNode();
      const analyser = audioContext.createAnalyser();
      node.connect(analyser);
      analyser.connect(audioContext.destination);
      workletNodeRef.current = node;
      analyserRef.current = analyser;
      setIsReady(true);
      if (audioContext.state === 'suspended') await audioContext.resume();
      drawVisualizer();
    }
  };

  const drawVisualizer = () => {
    if (!canvasRef.current || !analyserRef.current) return;
    const ctx = canvasRef.current.getContext('2d');
    if (!ctx) return;
    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);

    const render = () => {
      analyserRef.current!.getByteFrequencyData(dataArray);
      ctx.clearRect(0, 0, canvasRef.current!.width, canvasRef.current!.height);
      const themeColor = style === Style.WizardRock ? '#a855f7' : '#f97316';
      ctx.fillStyle = themeColor;

      const barWidth = (canvasRef.current!.width / bufferLength) * 2.5;
      let x = 0;
      for (let i = 0; i < bufferLength; i++) {
        const barHeight = (dataArray[i] / 255) * canvasRef.current!.height;
        ctx.fillRect(x, canvasRef.current!.height - barHeight, barWidth, barHeight);
        x += barWidth + 1;
      }
      requestAnimationFrame(render);
    };
    render();
  };

  const handleGenerate = async () => {
    setIsGenerating(true);
    try {
      const comp = await generateComposition(raga, style, mood, 110, lyricsSeed);
      setActiveComp(comp);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleMagicLyrics = async () => {
    const l = await generateLyrics(raga, style, mood);
    setLyricsSeed(l);
  };

  const playComposition = () => {
    if (!activeComp || !workletNodeRef.current) return;
    setIsPlaying(true);
    const start = audioContext.currentTime;

    // Schedule Vocal Timeline
    activeComp.vocalTimeline.forEach(entry => {
      const timeOffset = entry.time;
      setTimeout(() => {
        workletNodeRef.current?.port.postMessage({
          freq: 440 * Math.pow(2, (entry.midi - 69) / 12),
          tonic: 440 * Math.pow(2, (60 - 69) / 12), // C4 tonic
          phoneme: entry.phoneme,
          bhakti: activeComp.mood === Mood.Bhakti,
          gender: vocalParams.gender
        });
      }, timeOffset * 1000);
    });

    // Handle end
    setTimeout(() => setIsPlaying(false), 4000); // 4 bar loop approx
  };

  return (
    <div className={`min-h-screen p-4 md:p-8 transition-colors duration-700 ${style === Style.WizardRock ? 'bg-indigo-950' : 'bg-stone-950'}`}>
      <header className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h1 className="text-4xl font-bold font-outfit text-white tracking-tight flex items-center gap-2">
            <span className={style === Style.WizardRock ? 'text-purple-400' : 'text-orange-400'}>RagaMidi</span>
            <span className="text-sm font-normal bg-white/10 px-2 py-0.5 rounded uppercase tracking-widest text-white/60">Neural v2.5</span>
          </h1>
          <p className="text-white/40 text-sm mt-1">AI-Powered Indian Classical Vocal & Sitar Synthesis</p>
        </div>
        {!isReady ? (
          <button 
            onClick={initEngine}
            className="px-6 py-3 bg-white text-black font-bold rounded-full hover:bg-white/90 transition-all flex items-center gap-2 glow-orange"
          >
            Connect Sound Engine
          </button>
        ) : (
          <div className="flex gap-2">
             <div className="h-3 w-3 rounded-full bg-green-500 animate-pulse mt-1"></div>
             <span className="text-green-500 font-medium uppercase text-xs tracking-widest">Master Engine Online</span>
          </div>
        )}
      </header>

      <main className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left Control Panel */}
        <div className="lg:col-span-4 space-y-6">
          <section className="glass-panel p-6 rounded-3xl glow-orange">
            <h2 className="text-lg font-semibold mb-4 text-white/90 flex items-center gap-2">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
              Composition Settings
            </h2>

            <div className="space-y-4">
              <div>
                <label className="text-xs uppercase tracking-widest text-white/40 mb-1 block">Raga Selection</label>
                <select 
                  value={raga} 
                  onChange={(e) => setRaga(e.target.value as Raga)}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-orange-500/50"
                >
                  {Object.values(Raga).map(r => <option key={r} value={r} className="bg-stone-900">{r}</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-xs uppercase tracking-widest text-white/40 mb-1 block">Style</label>
                  <select 
                    value={style} 
                    onChange={(e) => setStyle(e.target.value as Style)}
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-orange-500/50"
                  >
                    {Object.values(Style).map(s => <option key={s} value={s} className="bg-stone-900">{s}</option>)}
                  </select>
                </div>
                <div>
                  <label className="text-xs uppercase tracking-widest text-white/40 mb-1 block">Mood</label>
                  <select 
                    value={mood} 
                    onChange={(e) => setMood(e.target.value as Mood)}
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-orange-500/50"
                  >
                    {Object.values(Mood).map(m => <option key={m} value={m} className="bg-stone-900">{m}</option>)}
                  </select>
                </div>
              </div>

              <div>
                <label className="text-xs uppercase tracking-widest text-white/40 mb-1 block flex justify-between">
                  Lyric Seed
                  <button onClick={handleMagicLyrics} className="text-orange-400 hover:text-orange-300 transition-colors">✨ Magic Draft</button>
                </label>
                <textarea 
                  value={lyricsSeed}
                  onChange={(e) => setLyricsSeed(e.target.value)}
                  placeholder="The moon rises over the temple..."
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white h-24 focus:outline-none focus:border-orange-500/50"
                />
              </div>

              <button 
                onClick={handleGenerate}
                disabled={isGenerating || !isReady}
                className="w-full py-4 bg-orange-600 hover:bg-orange-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold rounded-2xl transition-all shadow-lg shadow-orange-900/20"
              >
                {isGenerating ? "Casting Neural Spell..." : "Generate Neural Track"}
              </button>
            </div>
          </section>

          <section className="glass-panel p-6 rounded-3xl">
            <h2 className="text-lg font-semibold mb-4 text-white/90">Vocalist Configuration</h2>
            <div className="space-y-4">
              <div className="flex gap-4">
                <button 
                  onClick={() => setVocalParams({...vocalParams, gender: 'male'})}
                  className={`flex-1 py-2 rounded-xl border ${vocalParams.gender === 'male' ? 'border-orange-500 bg-orange-500/10 text-orange-400' : 'border-white/10 text-white/40'}`}
                >
                  Male
                </button>
                <button 
                  onClick={() => setVocalParams({...vocalParams, gender: 'female'})}
                  className={`flex-1 py-2 rounded-xl border ${vocalParams.gender === 'female' ? 'border-orange-500 bg-orange-500/10 text-orange-400' : 'border-white/10 text-white/40'}`}
                >
                  Female
                </button>
              </div>
              <div>
                <label className="text-xs uppercase tracking-widest text-white/40 mb-1 block">Timbre Model</label>
                <select 
                  value={vocalParams.timbre} 
                  onChange={(e) => setVocalParams({...vocalParams, timbre: e.target.value as any})}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white"
                >
                  <option value="kishore" className="bg-stone-900">Classic Warm (Kishore)</option>
                  <option value="rafi" className="bg-stone-900">Bright Brilliant (Rafi)</option>
                </select>
              </div>
            </div>
          </section>
        </div>

        {/* Center/Right Performance Area */}
        <div className="lg:col-span-8 space-y-6">
          <div className="glass-panel p-8 rounded-[2rem] min-h-[500px] flex flex-col">
            {activeComp ? (
              <>
                <div className="flex justify-between items-start mb-8">
                  <div>
                    <h3 className="text-3xl font-bold font-outfit text-white mb-2">{activeComp.title}</h3>
