import { GoogleGenAI, Type } from "@google/genai";
import { Raga, Style, Mood, Composition } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const compositionSchema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING },
    melody: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midi: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        },
        required: ["midi", "start", "duration", "velocity"]
      }
    },
    bass: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midi: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        }
      }
    },
    drums: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midiNote: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        }
      }
    },
    vocalTimeline: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          time: { type: Type.NUMBER },
          midi: { type: Type.NUMBER },
          phoneme: { type: Type.STRING },
          emotion: { type: Type.STRING },
          duration: { type: Type.NUMBER }
        }
      }
    },
    lyrics: { type: Type.STRING }
  },
  required: ["title", "melody", "vocalTimeline", "lyrics"]
};

export async function generateComposition(
  raga: Raga,
  style: Style,
  mood: Mood,
  bpm: number,
  lyricsSeed: string
): Promise<Composition> {
  const prompt = `
    Compose a 4-bar musical piece.
    Raga: ${raga}
    Style: ${style}
    Mood: ${mood}
    BPM: ${bpm}
    Lyrics Seed: ${lyricsSeed}

    If style is Wizard Rock: Use distorted electric guitar feel for melody, driving bass, and big arena drums.
    If style is Classical: Use Sitar feel, rhythmic drones, and Tabla patterns.

    For Vocal Timeline: 
    - Map syllables to notes.
    - Use phonemes like 'aa', 'ee', 'oo', 'ka', 'ta'.
    - Apply 'Bhakti' emotion for devotional style.
    - Ensure Pakad (signature phrases) of ${raga} are followed.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: compositionSchema
    }
  });

  const data = JSON.parse(response.text);

  return {
    ...data,
    id: crypto.randomUUID(),
    raga,
    style,
    mood,
    bpm,
    timestamp: Date.now()
  };
}

export async function generateLyrics(raga: Raga, style: Style, mood: Mood): Promise<string> {
  const prompt = `Generate a 2-line lyrical couplet for a song in Raag ${raga}. Style: ${style}, Mood: ${mood}. Output only the lyrics in Hindi/English transliteration.`;
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt
  });
  return response.text.trim();
}

import { Composition } from "../types";

const STORAGE_KEY = "ragamidi_compositions";

export function saveToLibrary(comp: Composition) {
  const existing = getLibrary();
  const updated = [comp, ...existing];
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
}

export function getLibrary(): Composition[] {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : [];
}

export function deleteFromLibrary(id: string) {
  const existing = getLibrary();
  const updated = existing.filter(c => c.id !== id);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
}

