                      {isPlaying ? (
                        <div className="flex gap-1 items-center">
                          <div className="h-4 w-1 bg-black animate-bounce"></div>
                          <div className="h-6 w-1 bg-black animate-bounce delay-75"></div>
                          <div className="h-4 w-1 bg-black animate-bounce delay-150"></div>
                        </div>
                      ) : (
                        <svg className="w-8 h-8 ml-1" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z" /></svg>
                      )}
                    </button>
                  </div>
                </div>

                <div className="space-y-4">
                  <div className="flex items-center gap-4">
                    <span className="text-xs uppercase tracking-widest text-white/20 whitespace-nowrap">Lyrics Display</span>
                    <div className="h-px bg-white/10 w-full"></div>
                  </div>
                  <p className="text-xl font-outfit text-white/80 italic leading-relaxed text-center">
                    "{activeComp.lyrics}"
                  </p>
                </div>
              </>
            ) : (
              <div className="flex-1 flex flex-col items-center justify-center text-center space-y-6 opacity-40">
                <div className="w-24 h-24 border-4 border-dashed border-white/20 rounded-full flex items-center justify-center">
                  <svg className="w-10 h-10 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>
                </div>
                <p className="text-white max-w-xs">Generate your first composition to unlock the neural stage and visualizer.</p>
              </div>
            )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <section className="glass-panel p-6 rounded-3xl">
              <h4 className="text-sm font-bold text-white/40 uppercase tracking-widest mb-4">Composition Library</h4>
              <div className="space-y-3 max-h-64 overflow-y-auto pr-2 custom-scrollbar">
                {library.length > 0 ? library.map(comp => (
                  <div key={comp.id} className="p-4 bg-white/5 rounded-2xl flex justify-between items-center group">
                    <div onClick={() => setActiveComp(comp)} className="cursor-pointer">
                      <p className="text-white font-medium group-hover:text-orange-400 transition-colors">{comp.title}</p>
                      <p className="text-white/30 text-xs">Raag {comp.raga} • {new Date(comp.timestamp).toLocaleDateString()}</p>
                    </div>
                    <button onClick={() => { deleteFromLibrary(comp.id); setLibrary(getLibrary()); }} className="opacity-0 group-hover:opacity-100 p-2 text-red-500 hover:text-red-400 transition-all">
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                  </div>
                )) : (
                  <p className="text-white/20 text-sm text-center py-8 italic">No saved spells in the grimoire yet.</p>
                )}
              </div>
            </section>

            <section className="glass-panel p-6 rounded-3xl flex flex-col justify-between">
              <div>
                <h4 className="text-sm font-bold text-white/40 uppercase tracking-widest mb-4">DAW Integration</h4>
                <p className="text-white/60 text-sm mb-4">Export high-fidelity MIDI files and drag them directly into FL Studio, Ableton, or Logic Pro. Mapped for VST instruments.</p>
              </div>
              <div className="flex gap-2">
                <span className="bg-orange-500/10 text-orange-400 text-[10px] px-2 py-1 rounded-md uppercase font-bold border border-orange-500/20">Sitar VST Ready</span>
                <span className="bg-purple-500/10 text-purple-400 text-[10px] px-2 py-1 rounded-md uppercase font-bold border border-purple-500/20">Tabla Mapped</span>
              </div>
            </section>
          </div>
        </div>
      </main>

      <footer className="max-w-7xl mx-auto mt-12 pb-8 text-center border-t border-white/5 pt-8">
        <p className="text-white/20 text-xs">RagaMidi Neural Engine © 2025 • Powered by Gemini AI & AudioWorklet DSP</p>
      </footer>
    </div>
  );
}

