import React, { useState, useEffect, useRef } from 'react';
import { Raga, Style, Mood, Composition, VocalParams, VocalPreset } from './types';
import { loadProcessor, createPluginNode, audioContext } from './audioContext';
import { generateComposition, generateLyrics } from './services/geminiService';
import { saveToLibrary, getLibrary, deleteFromLibrary, savePreset, getPresets, deletePreset } from './services/storageService';
import { exportMidiFile } from './services/midiService';

export default function App() {
  const [activeComp, setActiveComp] = useState<Composition | null>(null);
  const [library, setLibrary] = useState<Composition[]>([]);
  const [presets, setPresets] = useState<VocalPreset[]>([]);
  const [raga, setRaga] = useState<Raga>(Raga.Yaman);
  const [style, setStyle] = useState<Style>(Style.Classical);
  const [mood, setMood] = useState<Mood>(Mood.Peaceful);
  const [lyricsSeed, setLyricsSeed] = useState("");
  const [vocalParams, setVocalParams] = useState<VocalParams>({
    vibrato: 0.5,
    grit: 0.1,
    ornamentation: "meend",
    timbre: "kishore",
    gender: "male"
  });
  const [newPresetName, setNewPresetName] = useState("");
  const [isPlaying, setIsPlaying] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isReady, setIsReady] = useState(false);

  const workletNodeRef = useRef<AudioWorkletNode | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    setLibrary(getLibrary());
    setPresets(getPresets());
  }, []);

  const initEngine = async () => {
    const success = await loadProcessor();
    if (success) {
      const node = createPluginNode();
      const analyser = audioContext.createAnalyser();
      node.connect(analyser);
      analyser.connect(audioContext.destination);
      workletNodeRef.current = node;
      analyserRef.current = analyser;
      setIsReady(true);
      if (audioContext.state === 'suspended') await audioContext.resume();
      drawVisualizer();
    }
  };

  const drawVisualizer = () => {
    if (!canvasRef.current || !analyserRef.current) return;
    const ctx = canvasRef.current.getContext('2d');
    if (!ctx) return;
    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);

    const render = () => {
      analyserRef.current!.getByteFrequencyData(dataArray);
      ctx.clearRect(0, 0, canvasRef.current!.width, canvasRef.current!.height);
      const themeColor = style === Style.WizardRock ? '#a855f7' : '#f97316';
      ctx.fillStyle = themeColor;

      const barWidth = (canvasRef.current!.width / bufferLength) * 2.5;
      let x = 0;
      for (let i = 0; i < bufferLength; i++) {
        const barHeight = (dataArray[i] / 255) * canvasRef.current!.height;
        ctx.fillRect(x, canvasRef.current!.height - barHeight, barWidth, barHeight);
        x += barWidth + 1;
      }
      requestAnimationFrame(render);
    };
    render();
  };

  const handleGenerate = async () => {
    setIsGenerating(true);
    try {
      const comp = await generateComposition(raga, style, mood, 110, lyricsSeed);
      setActiveComp(comp);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleMagicLyrics = async () => {
    const l = await generateLyrics(raga, style, mood);
    setLyricsSeed(l);
  };

  const handleSavePreset = () => {
    if (!newPresetName.trim()) return;
    const preset: VocalPreset = {
      id: crypto.randomUUID(),
      name: newPresetName,
      params: { ...vocalParams }
    };
    savePreset(preset);
    setPresets(getPresets());
    setNewPresetName("");
  };

  const handleLoadPreset = (preset: VocalPreset) => {
    setVocalParams(preset.params);
  };

  const handleDeletePreset = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    deletePreset(id);
    setPresets(getPresets());
  };

  const playComposition = () => {
    if (!activeComp || !workletNodeRef.current) return;
    setIsPlaying(true);

    // Schedule Vocal Timeline
    activeComp.vocalTimeline.forEach(entry => {
      const timeOffset = entry.time;
      setTimeout(() => {
        workletNodeRef.current?.port.postMessage({
          freq: 440 * Math.pow(2, (entry.midi - 69) / 12),
          tonic: 440 * Math.pow(2, (60 - 69) / 12),
          phoneme: entry.phoneme,
          bhakti: activeComp.mood === Mood.Bhakti,
          gender: vocalParams.gender,
          gamak: vocalParams.ornamentation === "gamak"
        });
      }, timeOffset * 1000);
    });

    setTimeout(() => setIsPlaying(false), (activeComp.vocalTimeline[activeComp.vocalTimeline.length - 1]?.time || 0) * 1000 + 1000 || 4000);
  };

  return (
    <div className={`min-h-screen p-4 md:p-8 transition-colors duration-700 ${style === Style.WizardRock ? 'bg-indigo-950' : 'bg-stone-950'}`}>
      <header className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h1 className="text-4xl font-bold font-outfit text-white tracking-tight flex items-center gap-2">
            <span className={style === Style.WizardRock ? 'text-purple-400' : 'text-orange-400'}>RagaMidi</span>
            <span className="text-sm font-normal bg-white/10 px-2 py-0.5 rounded uppercase tracking-widest text-white/60">Neural v2.5</span>
          </h1>
          <p className="text-white/40 text-sm mt-1">AI-Powered Indian Classical Vocal & Sitar Synthesis</p>
        </div>
        {!isReady ? (
          <button 
            onClick={initEngine}
            className="px-6 py-3 bg-white text-black font-bold rounded-full hover:bg-white/90 transition-all flex items-center gap-2 glow-orange"
          >
            Connect Sound Engine
          </button>
        ) : (
          <div className="flex gap-2">
             <div className="h-3 w-3 rounded-full bg-green-500 animate-pulse mt-1"></div>
             <span className="text-green-500 font-medium uppercase text-xs tracking-widest">Master Engine Online</span>
          </div>
        )}
      </header>

      <main className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-4 space-y-6">
          <section className="glass-panel p-6 rounded-3xl glow-orange">
            <h2 className="text-lg font-semibold mb-4 text-white/90 flex items-center gap-2">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
              Composition Settings
            </h2>

            <div className="space-y-4">
              <div>
                <label className="text-xs uppercase tracking-widest text-white/40 mb-1 block">Raga Selection</label>
                <select 
                  value={raga} 
                  onChange={(e) => setRaga(e.target.value as Raga)}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-orange-500/50"
                >
                  {Object.values(Raga).sort().map(r => <option key={r} value={r} className="bg-stone-900">{r}</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-xs uppercase tracking-widest text-white/40 mb-1 block">Style</label>
                  <select 
                    value={style} 
                    onChange={(e) => setStyle(e.target.value as Style)}
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-orange-500/50"
                  >
                    {Object.values(Style).map(s => <option key={s} value={s} className="bg-stone-900">{s}</option>)}
                  </select>
                </div>
                <div>
                  <label className="text-xs uppercase tracking-widest text-white/40 mb-1 block">Mood</label>
                  <select 
                    value={mood} 
                    onChange={(e) => setMood(e.target.value as Mood)}
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-orange-500/50"
                  >
                    {Object.values(Mood).map(m => <option key={m} value={m} className="bg-stone-900">{m}</option>)}
                  </select>
                </div>
              </div>

              <div>
                <label className="text-xs uppercase tracking-widest text-white/40 mb-1 block flex justify-between">
                  Lyric Seed
                  <button onClick={handleMagicLyrics} className="text-orange-400 hover:text-orange-300 transition-colors">✨ Magic Draft</button>
                </label>
                <textarea 
                  value={lyricsSeed}
                  onChange={(e) => setLyricsSeed(e.target.value)}
                  placeholder="The moon rises over the temple..."
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white h-24 focus:outline-none focus:border-orange-500/50"
                />
              </div>

              <button 
                onClick={handleGenerate}
                disabled={isGenerating || !isReady}
                className="w-full py-4 bg-orange-600 hover:bg-orange-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold rounded-2xl transition-all shadow-lg shadow-orange-900/20"
              >
                {isGenerating ? "Casting Neural Spell..." : "Generate Neural Track"}
              </button>
            </div>
          </section>

          <section className="glass-panel p-6 rounded-3xl">
            <h2 className="text-lg font-semibold mb-4 text-white/90">Vocalist Configuration</h2>
            <div className="space-y-4">
              <div className="flex gap-4">
                <button 
                  onClick={() => setVocalParams({...vocalParams, gender: 'male'})}
                  className={`flex-1 py-2 rounded-xl border ${vocalParams.gender === 'male' ? 'border-orange-500 bg-orange-500/10 text-orange-400' : 'border-white/10 text-white/40'}`}
                >
                  Male
                </button>
                <button 
                  onClick={() => setVocalParams({...vocalParams, gender: 'female'})}
                  className={`flex-1 py-2 rounded-xl border ${vocalParams.gender === 'female' ? 'border-orange-500 bg-orange-500/10 text-orange-400' : 'border-white/10 text-white/40'}`}
                >
                  Female
                </button>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] uppercase tracking-widest text-white/40">Vibrato</label>
                  <input 
                    type="range" min="0" max="1" step="0.01" 
                    value={vocalParams.vibrato}
                    onChange={(e) => setVocalParams({...vocalParams, vibrato: parseFloat(e.target.value)})}
                    className="w-full accent-orange-500"
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] uppercase tracking-widest text-white/40">Grit</label>
                  <input 
                    type="range" min="0" max="1" step="0.01" 
                    value={vocalParams.grit}
                    onChange={(e) => setVocalParams({...vocalParams, grit: parseFloat(e.target.value)})}
                    className="w-full accent-orange-500"
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
