                  <div className="flex gap-3">
                    <button 
                      onClick={() => { saveToLibrary(activeComp); setLibrary(getLibrary()); }}
                      className="p-3 bg-white/5 hover:bg-white/10 rounded-full border border-white/10 text-white/60 transition-colors"
                    >
                      <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 5a2 2 0 012-2h10a2 2 0 012 2v16l-7-3.5L5 21V5z" /></svg>
                    </button>
                    <button 
                      onClick={() => exportMidiFile(activeComp)}
                      className="px-6 py-3 bg-white/10 hover:bg-white/20 rounded-full border border-white/10 text-white font-medium transition-colors flex items-center gap-2"
                    >
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                      MIDI
                    </button>
                  </div>
                </div>

                <div className="flex-1 bg-black/40 rounded-3xl mb-8 relative overflow-hidden group">
                  <canvas ref={canvasRef} width={800} height={300} className="w-full h-full object-cover" />
                  <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-black/20 backdrop-blur-sm">
                    <button 
                      onClick={playComposition}
                      disabled={isPlaying}
                      className="w-20 h-20 bg-white text-black rounded-full flex items-center justify-center shadow-2xl hover:scale-110 transition-transform disabled:scale-100 disabled:opacity-50"
                    >
                      {isPlaying ? (
                        <div className="flex gap-1 items-center">
                          <div className="h-4 w-1 bg-black animate-bounce"></div>
                          <div className="h-6 w-1 bg-black animate-bounce delay-75"></div>
