export const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
  sampleRate: 44100,
  latencyHint: 'interactive'
});

let workletLoaded = false;

export async function loadProcessor() {
  if (workletLoaded) return true;

  const WORKLET_CODE = `
    const clamp = (v, a, b) => Math.max(a, Math.min(b, v));

    class PitchSmoother {
      constructor() { this.current = 220; }
      step(target) {
        const diff = target - this.current;
        this.current += diff * 0.005; 
        return this.current;
      }
    }

    class GlottalSource {
      constructor(sr) {
        this.sr = sr;
        this.phase = 0;
      }
      process(freq) {
        if (freq <= 0) return 0;
        const T = this.sr / freq;
        this.phase++;
        if (this.phase >= T) this.phase = 0;

        const open = 0.4 * T;
        const close = 0.16 * T;

        if (this.phase < open) {
          const x = this.phase / open;
          return 0.5 * (1 - Math.cos(Math.PI * x));
        }
        if (this.phase < open + close) {
          const x = (this.phase - open) / close;
          return Math.cos(Math.PI * x);
        }
        return 0;
      }
    }

    class BandPass {
      constructor(sr) {
        this.sr = sr;
        this.y1 = this.y2 = 0;
      }
      set(f, bw) {
        const w = 2 * Math.PI * f / this.sr;
        const r = Math.exp(-Math.PI * bw / this.sr);
        this.a1 = 2 * r * Math.cos(w);
        this.a2 = -r * r;
        this.b0 = 1 - r;
      }
      process(x) {
        const y = this.b0 * x + this.a1 * this.y1 + this.a2 * this.y2;
        this.y2 = this.y1;
        this.y1 = y;
        return y;
      }
    }

    class FormantFilter {
      constructor(sr) {
        this.sr = sr;
        this.bands = Array.from({ length: 5 }, () => new BandPass(sr));
        this.vowelData = {
          aa: [700, 1220, 2600, 3500, 4500],
          ee: [300, 2200, 3000, 3600, 4200],
          oo: [400, 800, 2400, 3200, 4000]
        };
        this.setVowel("aa");
      }
      setVowel(v) {
        const freqs = this.vowelData[v] || this.vowelData.aa;
        freqs.forEach((f, i) => this.bands[i].set(f, 90 + i * 50));
      }
      process(x, gain = 1.0) {
        return this.bands.reduce((s, b) => s + b.process(x), 0) * 0.25 * gain;
      }
    }

    class VocalProcessor extends AudioWorkletProcessor {
      constructor() {
        super();
        this.pitch = new PitchSmoother();
        this.glottal = new GlottalSource(sampleRate);
        this.formant = new FormantFilter(sampleRate);

        this.state = {
          freq: 220,
          tonic: 220,
          ragaShruti: [0, 200, 400, 500, 700, 900, 1100],
          gamak: false,
          phoneme: "aa",
          bhakti: false,
          gender: "male",
          gain: 0 // New gain control
        };

        this.currentGain = 0;
        this.time = 0;
        this.port.onmessage = e => Object.assign(this.state, e.data);
      }

      snapToRaga(freq) {
        if (freq <= 0) return 0;
        const cents = 1200 * Math.log2(freq / this.state.tonic);
        let best = cents, min = 1e9;
        for (const s of this.state.ragaShruti) {
          const d = Math.abs(cents - s);
          if (d < min) { min = d; best = s; }
        }
        return this.state.tonic * Math.pow(2, best / 1200);
      }

      process(_, outputs) {
        const out = outputs[0][0];
        const { freq, gamak, phoneme, bhakti, gender, gain } = this.state;

        for (let i = 0; i < out.length; i++) {
          // Smooth gain to prevent clicks
          this.currentGain += (gain - this.currentGain) * 0.005;

          let f = this.snapToRaga(freq);
          if (gamak && f > 0) {
            f *= (1 + 0.015 * Math.sin(2 * Math.PI * 6.5 * this.time));
          }

          const targetFreq = this.pitch.step(f);
          let sig = this.glottal.process(targetFreq);

          this.formant.setVowel(phoneme === "ka" || phoneme === "ta" ? "aa" : phoneme);

          let fGain = bhakti ? 1.15 : 1.0;
          if (gender === "female") fGain *= 0.8;

          sig = this.formant.process(sig, fGain);

          if (bhakti && this.currentGain > 0.01) {
            sig += (Math.random() * 2 - 1) * 0.04;
            sig = Math.tanh(sig * 2.2);
          }

          out[i] = sig * 0.4 * this.currentGain;
          this.time += 1 / sampleRate;
        }
        return true;
      }
    }

    registerProcessor("vocal-processor", VocalProcessor);
  `;

  const blob = new Blob([WORKLET_CODE], { type: 'application/javascript' });
  const url = URL.createObjectURL(blob);

  try {
    await audioContext.audioWorklet.addModule(url);
    workletLoaded = true;
    return true;
  } catch (err) {
    console.error("Failed to load AudioWorklet", err);
    return false;
  }
}

export function createPluginNode() {
  return new AudioWorkletNode(audioContext, "vocal-processor");
}

import { Composition } from "../types";

export interface MidiExportOptions {
  tempo?: number;
  timeSignature?: [number, number];
  tracks: {
    melody: boolean;
    bass: boolean;
    drums: boolean;
  };
}

function encodeVLQ(num: number): number[] {
  const result: number[] = [];
  let n = Math.floor(num);
  result.unshift(n & 0x7F);
  while (n > 127) {
    n >>= 7;
    result.unshift((n & 0x7F) | 0x80);
  }
  return result;
}

export function exportMidiFile(comp: Composition, options: MidiExportOptions) {
  const PPQ = 480;
  const tracks: number[][] = [];

  // 1. CONCONDUCTOR TRACK (Tempo / Time Sig)
  const conductorEvents: { time: number; data: number[] }[] = [];

  // Set Tempo
  const bpm = options.tempo || comp.bpm || 120;
  const microsecondsPerBeat = Math.floor(60000000 / bpm);
  conductorEvents.push({
    time: 0,
    data: [0xFF, 0x51, 0x03, 
      (microsecondsPerBeat >> 16) & 0xFF,
      (microsecondsPerBeat >> 8) & 0xFF,
      microsecondsPerBeat & 0xFF
    ]
  });

  // Set Time Signature
  const [num, den] = options.timeSignature || [4, 4];
  const denominatorPower = Math.log2(den);
  conductorEvents.push({
    time: 0,
    data: [0xFF, 0x58, 0x04, num, denominatorPower, 24, 8]
  });

  tracks.push(serializeTrack(conductorEvents));

  // 2. MELODY TRACK
  if (options.tracks.melody) {
    const melodyEvents: { time: number; data: number[] }[] = [];
    comp.melody.forEach(note => {
      melodyEvents.push({ time: Math.floor(note.start * PPQ), data: [0x90, note.midi, note.velocity] });
      melodyEvents.push({ time: Math.floor((note.start + note.duration) * PPQ), data: [0x80, note.midi, 0] });
    });
    tracks.push(serializeTrack(melodyEvents));
  }

  // 3. BASS TRACK
  if (options.tracks.bass && comp.bass) {
    const bassEvents: { time: number; data: number[] }[] = [];
    comp.bass.forEach(note => {
      bassEvents.push({ time: Math.floor(note.start * PPQ), data: [0x91, note.midi, note.velocity] });
      bassEvents.push({ time: Math.floor((note.start + note.duration) * PPQ), data: [0x81, note.midi, 0] });
    });
    tracks.push(serializeTrack(bassEvents));
  }

  // 4. DRUM TRACK
  if (options.tracks.drums && comp.drums) {
    const drumEvents: { time: number; data: number[] }[] = [];
    comp.drums.forEach(note => {
      drumEvents.push({ time: Math.floor(note.start * PPQ), data: [0x99, note.midiNote, note.velocity] });
      drumEvents.push({ time: Math.floor((note.start + note.duration) * PPQ), data: [0x89, note.midiNote, 0] });
    });
    tracks.push(serializeTrack(drumEvents));
  }

  function serializeTrack(events: { time: number; data: number[] }[]): number[] {
    events.sort((a, b) => a.time - b.time);
    let data: number[] = [];
    let lastTick = 0;
    events.forEach(e => {
      const delta = e.time - lastTick;
      data.push(...encodeVLQ(delta));
      data.push(...e.data);
      lastTick = e.time;
    });
    data.push(0x00, 0xFF, 0x2F, 0x00); // EOT
    return [
      0x4d, 0x54, 0x72, 0x6b,
      (data.length >> 24) & 0xFF,
      (data.length >> 16) & 0xFF,
      (data.length >> 8) & 0xFF,
      data.length & 0xFF,
      ...data
    ];
  }

  const header = [
    0x4d, 0x54, 0x68, 0x64,
    0x00, 0x00, 0x00, 0x06,
    0x00, 0x01, // Type 1 (multi-track)
    (tracks.length >> 8) & 0xFF,
    tracks.length & 0xFF,
    (PPQ >> 8) & 0xFF,
    PPQ & 0xFF
  ];

  const blob = new Blob([new Uint8Array([...header, ...tracks.flat()])], { type: "audio/midi" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${comp.title.replace(/\s+/g, '_')}_v2.mid`;
  a.click();
}

import React, { useState, useEffect, useRef } from 'react';
import { Raga, Style, Mood, Composition, VocalParams, VocalPreset } from './types';
import { loadProcessor, createPluginNode, audioContext } from './audioContext';
import { generateComposition, generateLyrics } from './services/geminiService';
import { saveToLibrary, getLibrary, deleteFromLibrary, savePreset, getPresets, deletePreset } from './services/storageService';
import { exportMidiFile, MidiExportOptions } from './services/midiService';
import { getRagaShruti } from './constants';

export default function App() {
  const [activeComp, setActiveComp] = useState<Composition | null>(null);
  const [library, setLibrary] = useState<Composition[]>([]);
  const [presets, setPresets] = useState<VocalPreset[]>([]);
  const [raga, setRaga] = useState<Raga>(Raga.Yaman);
  const [style, setStyle] = useState<Style>(Style.Classical);
  const [mood, setMood] = useState<Mood>(Mood.Peaceful);
  const [lyricsSeed, setLyricsSeed] = useState("");
  const [vocalParams, setVocalParams] = useState<VocalParams>({
    vibrato: 0.5,
    grit: 0.1,
    ornamentation: "meend",
    timbre: "kishore",
    gender: "male"
  });
  const [newPresetName, setNewPresetName] = useState("");
  const [isPlaying, setIsPlaying] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isReady, setIsReady] = useState(false);

  // MIDI Export Options
  const [exportOptions, setExportOptions] = useState<MidiExportOptions>({
    tempo: 110,
    timeSignature: [4, 4],
    tracks: { melody: true, bass: true, drums: true }
  });
  const [showMidiSettings, setShowMidiSettings] = useState(false);

  const workletNodeRef = useRef<AudioWorkletNode | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const playbackTimersRef = useRef<number[]>([]);

  useEffect(() => {
    setLibrary(getLibrary());
    setPresets(getPresets());
    return () => {
      playbackTimersRef.current.forEach(clearTimeout);
    };
  }, []);

  const initEngine = async () => {
    if (audioContext.state === 'suspended') {
        await audioContext.resume();
    }
    const success = await loadProcessor();
    if (success) {
      const node = createPluginNode();
      const analyser = audioContext.createAnalyser();
      node.connect(analyser);
      analyser.connect(audioContext.destination);
      workletNodeRef.current = node;
      analyserRef.current = analyser;
      setIsReady(true);
      drawVisualizer();
      return true;
    }
    return false;
  };

  const drawVisualizer = () => {
    if (!canvasRef.current || !analyserRef.current) return;
    const ctx = canvasRef.current.getContext('2d');
    if (!ctx) return;
    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);

    const render = () => {
      if (!analyserRef.current) return;
      analyserRef.current.getByteFrequencyData(dataArray);
      ctx.clearRect(0, 0, canvasRef.current!.width, canvasRef.current!.height);
      const themeColor = style === Style.WizardRock ? '#a855f7' : '#f97316';
      ctx.fillStyle = themeColor;

      const barWidth = (canvasRef.current!.width / bufferLength) * 2.5;
      let x = 0;
      for (let i = 0; i < bufferLength; i++) {
        const barHeight = (dataArray[i] / 255) * canvasRef.current!.height;
        ctx.fillRect(x, canvasRef.current!.height - barHeight, barWidth, barHeight);
        x += barWidth + 1;
      }
      requestAnimationFrame(render);
    };
    render();
  };

  const playComposition = (compToPlay?: Composition) => {
    const comp = compToPlay || activeComp;
    if (!comp || !workletNodeRef.current) return;

    playbackTimersRef.current.forEach(clearTimeout);
    playbackTimersRef.current = [];

    setIsPlaying(true);
    const shruti = getRagaShruti(comp.raga);

    comp.vocalTimeline.forEach(entry => {
      // START NOTE
      const startTimer = window.setTimeout(() => {
        workletNodeRef.current?.port.postMessage({
          freq: 440 * Math.pow(2, (entry.midi - 69) / 12),
          tonic: 440 * Math.pow(2, (60 - 69) / 12), 
          ragaShruti: shruti,
          phoneme: entry.phoneme,
          bhakti: comp.mood === Mood.Bhakti,
          gender: vocalParams.gender,
          gamak: vocalParams.ornamentation === "gamak",
          gain: 1.0 // Turn gain on
        });
      }, entry.time * 1000);
      playbackTimersRef.current.push(startTimer);

      // END NOTE
      const endTimer = window.setTimeout(() => {
        workletNodeRef.current?.port.postMessage({ gain: 0 }); // Turn gain off
      }, (entry.time + entry.duration) * 1000);
      playbackTimersRef.current.push(endTimer);
    });

    const finishTimer = window.setTimeout(() => {
      setIsPlaying(false);
    }, (comp.vocalTimeline[comp.vocalTimeline.length - 1]?.time || 0) * 1000 + 1000 + 1000);
    playbackTimersRef.current.push(finishTimer);
  };

  const handleGenerate = async () => {
    if (!isReady) {
      const ok = await initEngine();
      if (!ok) return;
    }

    setIsGenerating(true);
    try {
      const comp = await generateComposition(raga, style, mood, 110, lyricsSeed);
      setActiveComp(comp);
      playComposition(comp);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSaveToLibrary = (comp: Composition) => {
    saveToLibrary(comp);
    setLibrary(getLibrary());
  };

