import { GoogleGenAI, Type } from "@google/genai";
import { Raga, Style, Mood, Composition } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const compositionSchema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING },
    melody: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midi: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        },
        required: ["midi", "start", "duration", "velocity"]
      }
    },
    bass: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midi: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        }
      }
    },
    drums: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midiNote: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        }
      }
    },
    vocalTimeline: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          time: { type: Type.NUMBER },
          midi: { type: Type.NUMBER },
          phoneme: { type: Type.STRING },
          emotion: { type: Type.STRING },
          duration: { type: Type.NUMBER }
        }
      }
    },
    lyrics: { type: Type.STRING }
  },
  required: ["title", "melody", "vocalTimeline", "lyrics"]
};

export async function generateComposition(
  raga: Raga,
  style: Style,
  mood: Mood,
  bpm: number,
  lyricsSeed: string
): Promise<Composition> {
  const prompt = `
    Compose a detailed 4-bar musical piece. 
    IMPORTANT: The vocalTimeline MUST contain a sequence of many distinct notes (8-16 notes) following the lyrics, not just a single long note.

    Raga: ${raga}
    Style: ${style}
    Mood: ${mood}
    BPM: ${bpm}
    Lyrics Seed: ${lyricsSeed}

    Technical requirements:
    - melody: A lead phrase for the raga.
    - vocalTimeline: Each syllable of the lyrics should correspond to a note with a specific duration (e.g. 0.25 to 1.0 seconds).
    - phonemes: Use 'aa', 'ee', 'oo', 'ka', 'ta'.
    - If style is Wizard Rock: Use driving bass and big arena drums.
    - If style is Classical: Use Tabla-like patterns in drums and drone bass.

    Ensure the melody and vocalTimeline notes strictly follow the swaras of Raag ${raga}.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: compositionSchema
    }
  });

  const data = JSON.parse(response.text);

  return {
    ...data,
    id: crypto.randomUUID(),
    raga,
    style,
    mood,
    bpm,
    timestamp: Date.now()
  };
}

export async function generateLyrics(raga: Raga, style: Style, mood: Mood): Promise<string> {
  const prompt = `Generate a 2-line lyrical couplet for a song in Raag ${raga}. Style: ${style}, Mood: ${mood}. Output only the lyrics in Hindi/English transliteration.`;
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt
  });
  return response.text.trim();
}

import { Composition } from "../types";

export interface MidiExportOptions {
  tempo?: number;
  timeSignature?: [number, number];
  tracks: {
    melody: boolean;
    bass: boolean;
    drums: boolean;
  };
}

function encodeVLQ(num: number): number[] {
  const result: number[] = [];
  let n = Math.floor(num);
  result.unshift(n & 0x7F);
  while (n > 127) {
    n >>= 7;
    result.unshift((n & 0x7F) | 0x80);
  }
  return result;
}

export function exportMidiFile(comp: Composition, options: MidiExportOptions) {
  const PPQ = 480;
  const tracks: number[][] = [];

  // 1. CONDUCTOR TRACK (Tempo / Time Sig)
  const conductorEvents: { time: number; data: number[] }[] = [];

  // Set Tempo Meta Event (microseconds per quarter note)
  const bpm = options.tempo || comp.bpm || 120;
  const microsecondsPerBeat = Math.floor(60000000 / bpm);
  conductorEvents.push({
    time: 0,
    data: [0xFF, 0x51, 0x03, 
      (microsecondsPerBeat >> 16) & 0xFF,
      (microsecondsPerBeat >> 8) & 0xFF,
      microsecondsPerBeat & 0xFF
    ]
  });

  // Set Time Signature Meta Event
  const [num, den] = options.timeSignature || [4, 4];
  const denominatorPower = Math.log2(den); // 4 -> 2, 8 -> 3
  conductorEvents.push({
    time: 0,
    data: [0xFF, 0x58, 0x04, num, denominatorPower, 24, 8]
  });

  tracks.push(serializeTrack(conductorEvents));

  // 2. MELODY TRACK (Neural Leads)
  if (options.tracks.melody) {
    const melodyEvents: { time: number; data: number[] }[] = [];
    comp.melody.forEach(note => {
      melodyEvents.push({ time: Math.floor(note.start * PPQ), data: [0x90, note.midi, note.velocity] });
      melodyEvents.push({ time: Math.floor((note.start + note.duration) * PPQ), data: [0x80, note.midi, 0] });
    });
    tracks.push(serializeTrack(melodyEvents));
  }

  // 3. BASS TRACK
  if (options.tracks.bass && comp.bass) {
    const bassEvents: { time: number; data: number[] }[] = [];
    comp.bass.forEach(note => {
      bassEvents.push({ time: Math.floor(note.start * PPQ), data: [0x91, note.midi, note.velocity] });
      bassEvents.push({ time: Math.floor((note.start + note.duration) * PPQ), data: [0x81, note.midi, 0] });
    });
    tracks.push(serializeTrack(bassEvents));
  }

  // 4. DRUM TRACK (Channel 10)
  if (options.tracks.drums && comp.drums) {
    const drumEvents: { time: number; data: number[] }[] = [];
    comp.drums.forEach(note => {
      drumEvents.push({ time: Math.floor(note.start * PPQ), data: [0x99, note.midiNote, note.velocity] });
      drumEvents.push({ time: Math.floor((note.start + note.duration) * PPQ), data: [0x89, note.midiNote, 0] });
    });
    tracks.push(serializeTrack(drumEvents));
  }

  function serializeTrack(events: { time: number; data: number[] }[]): number[] {
    events.sort((a, b) => a.time - b.time);
    let data: number[] = [];
    let lastTick = 0;
    events.forEach(e => {
      const delta = e.time - lastTick;
      data.push(...encodeVLQ(delta));
      data.push(...e.data);
      lastTick = e.time;
    });
    data.push(0x00, 0xFF, 0x2F, 0x00); // End of Track meta event

    return [
      0x4d, 0x54, 0x72, 0x6b, // MTrk
      (data.length >> 24) & 0xFF,
      (data.length >> 16) & 0xFF,
      (data.length >> 8) & 0xFF,
      data.length & 0xFF,
      ...data
    ];
  }

  const header = [
    0x4d, 0x54, 0x68, 0x64, // MThd
    0x00, 0x00, 0x00, 0x06, // Length of header
    0x00, 0x01,             // Type 1 (multi-track synchronous)
    (tracks.length >> 8) & 0xFF,
    tracks.length & 0xFF,
    (PPQ >> 8) & 0xFF,
    PPQ & 0xFF
  ];

  const blob = new Blob([new Uint8Array([...header, ...tracks.flat()])], { type: "audio/midi" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${comp.title.replace(/\s+/g, '_')}_midi_v2.mid`;
  a.click();
}

