              </div>
              <div className="grid grid-cols-2 gap-4">
                {['vibrato', 'grit'].map(p => (
                  <div key={p} className="space-y-1">
                    <label className="text-[10px] uppercase tracking-widest text-white/40">{p}</label>
                    <input 
