                 </div>
              </div>
            </div>
          </section>
        </div>

        <div className="lg:col-span-8 space-y-6">
          <div className="glass-panel p-8 rounded-[2rem] min-h-[500px] flex flex-col relative overflow-hidden">
            {activeComp ? (
              <>
                <div className="flex justify-between items-start mb-8 relative z-10">
