                  </div>
                </div>

                {showMidiSettings && (
                  <div className="absolute right-8 top-24 z-20 w-80 p-6 glass-panel rounded-3xl shadow-2xl border-orange-500/30 animate-in fade-in zoom-in duration-200">
                    <h4 className="text-xs font-bold text-white/40 uppercase tracking-[0.2em] mb-4">Export Configuration</h4>
                    <div className="space-y-4">
                      <div className="grid grid-cols-2 gap-3">
