                            <span className="text-white/20">/</span>
                            <input type="number" value={exportOptions.timeSignature![1]} onChange={e => setExportOptions({...exportOptions, timeSignature: [exportOptions.timeSignature![0], parseInt(e.target.value)]})} className="w-full bg-white/5 border border-white/10 rounded-lg px-2 py-2 text-white text-xs text-center"/>
                          </div>
                        </div>
                      </div>
                      <div className="space-y-2 border-t border-white/5 pt-3">
                         <p className="text-[9px] text-white/20 uppercase font-black mb-1">Select Tracks</p>
                         {(['melody', 'bass', 'drums'] as const).map(t => (
                           <label key={t} className="flex items-center justify-between gap-3 cursor-pointer group p-2 hover:bg-white/5 rounded-lg transition-colors">
                             <span className="text-xs text-white/60 group-hover:text-white capitalize">{t} Section</span>
                             <input type="checkbox" checked={exportOptions.tracks[t]} onChange={e => setExportOptions({...exportOptions, tracks: {...exportOptions.tracks, [t]: e.target.checked}})} className="w-4 h-4 rounded border-white/10 bg-white/5 accent-orange-500 cursor-pointer"/>
                           </label>
                         ))}
                      </div>
                      <button onClick={() => { exportMidiFile(activeComp, exportOptions); setShowMidiSettings(false); }} className="w-full py-3 bg-orange-600 hover:bg-orange-500 text-white rounded-xl text-xs font-bold transition-all shadow-lg shadow-orange-950/20 mt-2 uppercase tracking-widest">Download MIDI File</button>
                    </div>
                  </div>
                )}

                <div className="flex-1 bg-black/40 rounded-3xl mb-8 relative group border border-white/5 overflow-hidden">
                  <canvas ref={canvasRef} width={800} height={300} className="w-full h-full object-cover" />
                  <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-black/20 backdrop-blur-sm">
                    <button 
                      onClick={() => playComposition()}
                      disabled={isPlaying}
                      className="w-24 h-24 bg-white text-black rounded-full flex items-center justify-center shadow-2xl hover:scale-110 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100"
                    >
                      {isPlaying ? (
                        <div className="flex gap-1.5 items-center">
                          <div className="h-6 w-1.5 bg-black animate-bounce"></div>
                          <div className="h-8 w-1.5 bg-black animate-bounce delay-75"></div>
                          <div className="h-6 w-1.5 bg-black animate-bounce delay-150"></div>
                        </div>
                      ) : (
                        <svg className="w-10 h-10 ml-2" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z" /></svg>
                      )}
                    </button>
                  </div>
                  {isPlaying && (
                    <div className="absolute bottom-4 left-4 right-4 flex justify-center">
                       <div className="px-4 py-2 bg-black/60 backdrop-blur rounded-full border border-white/10 animate-pulse">
                         <span className="text-[10px] text-white/40 uppercase tracking-[0.3em] font-black">Neural Streaming Active</span>
