                </div>
                <div className="space-y-4 relative z-10">
                  <div className="flex items-center gap-4">
                    <span className="text-[10px] uppercase tracking-widest text-white/20 whitespace-nowrap font-black">AI Lyrics Transcription</span>
                    <div className="h-px bg-white/5 w-full"></div>
