            ) : (
              <div className="flex-1 flex flex-col items-center justify-center text-center space-y-8 opacity-40 py-20">
                <div className="w-32 h-32 border-2 border-dashed border-white/20 rounded-full flex items-center justify-center animate-pulse">
                   <svg className="w-12 h-12 text-white/30" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" /></svg>
                </div>
                <div className="space-y-2">
                  <h3 className="text-white font-bold text-xl">The Neural Stage is Quiet</h3>
                  <p className="text-white/40 max-w-xs text-sm mx-auto">Select a Raga and configuration above to generate an original composition with AI-synthesized vocals.</p>
                </div>
              </div>
            )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <section className="glass-panel p-6 rounded-3xl border border-white/5">
              <h4 className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] mb-4">Neural Library</h4>
              <div className="space-y-3 max-h-64 overflow-y-auto pr-2 custom-scrollbar">
                {library.map(comp => (
                  <div key={comp.id} className="p-4 bg-white/5 rounded-2xl flex justify-between items-center group hover:bg-white/10 transition-all border border-transparent hover:border-white/10">
                    <div onClick={() => { setActiveComp(comp); playComposition(comp); }} className="cursor-pointer flex-1">
                      <p className="text-white font-semibold text-sm group-hover:text-orange-400 transition-colors">{comp.title}</p>
                      <p className="text-white/20 text-[10px] uppercase tracking-widest mt-1">Raag {comp.raga} • {new Date(comp.timestamp).toLocaleDateString()}</p>
                    </div>
                    <button onClick={() => { deleteFromLibrary(comp.id); setLibrary(getLibrary()); }} className="opacity-0 group-hover:opacity-100 p-2 text-red-500/50 hover:text-red-500 transition-opacity">
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                  </div>
                ))}
                {library.length === 0 && <p className="text-center text-white/10 text-xs py-10 italic">Library is empty</p>}
              </div>
            </section>
            <section className="glass-panel p-8 rounded-3xl border-l-4 border-l-orange-500/60 flex flex-col justify-between">
              <div>
                <h4 className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] mb-4">Plugin Information</h4>
                <p className="text-white/60 text-xs leading-relaxed">
                  RagaMidi V2.5 uses high-order formant shaping and glottal flow modeling. MIDI exports now support meta events for DAW synchronization, multi-track separation, and variable time-signatures.
                </p>
              </div>
              <div className="flex gap-2 mt-6">
                 <span className="px-2 py-1 bg-white/5 rounded text-[8px] font-bold text-white/30 uppercase tracking-widest border border-white/10">Vocal v2.5.4</span>
                 <span className="px-2 py-1 bg-white/5 rounded text-[8px] font-bold text-white/30 uppercase tracking-widest border border-white/10">MIDI v2.0</span>
              </div>
            </section>
          </div>
        </div>
      </main>
      <footer className="max-w-7xl mx-auto mt-16 pb-12 border-t border-white/5 pt-8 text-center">
         <p className="text-[10px] text-white/20 uppercase tracking-[0.5em] font-medium">RagaMidi Engine © 2025 • DSP AudioWorklet • Gemini Pro Composer</p>
      </footer>
    </div>
  );
}

import { GoogleGenAI, Type } from "@google/genai";
import { Raga, Style, Mood, Composition } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const compositionSchema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING },
    melody: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midi: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        },
        required: ["midi", "start", "duration", "velocity"]
      }
    },
    bass: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midi: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        }
      }
    },
    drums: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midiNote: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        }
      }
    },
    vocalTimeline: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          time: { type: Type.NUMBER },
          midi: { type: Type.NUMBER },
          phoneme: { type: Type.STRING },
          emotion: { type: Type.STRING },
          duration: { type: Type.NUMBER }
        },
        required: ["time", "midi", "phoneme", "duration"]
      }
    },
    lyrics: { type: Type.STRING }
  },
  required: ["title", "melody", "vocalTimeline", "lyrics"]
};

export async function generateComposition(
  raga: Raga,
  style: Style,
  mood: Mood,
  bpm: number,
  lyricsSeed: string
): Promise<Composition> {
  const prompt = `
    Role: Expert Indian Classical Composer & MIDI Producer.
    Task: Compose a 4-bar Raga masterpiece.

    CRITICAL: The vocalTimeline MUST be a sequence of at least 12-20 distinct notes. DO NOT generate a single sustained note for the entire lyrics. Each syllable must be a new note with a specific duration (0.1s to 0.8s).

    Parameters:
    - Raga: ${raga} (Use its specific swara scale)
    - Style: ${style}
    - Mood: ${mood}
    - BPM: ${bpm}
    - Lyrics Context: ${lyricsSeed}

    Technical Details:
    - melody: The Sitar/Lead instrument track.
    - vocalTimeline: The Neural Vocalist's track. Must be intricate and phrased naturally.
    - phonemes: Strictly use 'aa', 'ee', 'oo', 'ka', 'ta'.
    - Bass & Drums: Generate appropriate backing for ${style}.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: compositionSchema
    }
  });

  const data = JSON.parse(response.text);

  return {
    ...data,
    id: crypto.randomUUID(),
    raga,
    style,
    mood,
    bpm,
    timestamp: Date.now()
  };
}

export async function generateLyrics(raga: Raga, style: Style, mood: Mood): Promise<string> {
  const prompt = `Generate a 2-line lyrical couplet for a song in Raag ${raga}. Style: ${style}, Mood: ${mood}. Output only the lyrics in Hindi/English transliteration.`;
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt
  });
  return response.text.trim();
}

import React, { useState, useEffect, useRef } from 'react';
import { Raga, Style, Mood, Composition, VocalParams, VocalPreset } from './types';
import { loadProcessor, createPluginNode, audioContext } from './audioContext';
import { generateComposition, generateLyrics } from './services/geminiService';
import { saveToLibrary, getLibrary, deleteFromLibrary, savePreset, getPresets, deletePreset } from './services/storageService';
import { exportMidiFile, MidiExportOptions } from './services/midiService';
import { getRagaShruti } from './constants';

export default function App() {
  const [activeComp, setActiveComp] = useState<Composition | null>(null);
  const [library, setLibrary] = useState<Composition[]>([]);
  const [presets, setPresets] = useState<VocalPreset[]>([]);
  const [raga, setRaga] = useState<Raga>(Raga.Yaman);
  const [style, setStyle] = useState<Style>(Style.Classical);
  const [mood, setMood] = useState<Mood>(Mood.Peaceful);
  const [lyricsSeed, setLyricsSeed] = useState("");
  const [vocalParams, setVocalParams] = useState<VocalParams>({
    vibrato: 0.5,
    grit: 0.1,
    ornamentation: "meend",
    timbre: "kishore",
    gender: "male"
  });
  const [newPresetName, setNewPresetName] = useState("");
  const [isPlaying, setIsPlaying] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isReady, setIsReady] = useState(false);

  // MIDI Export Options
  const [exportOptions, setExportOptions] = useState<MidiExportOptions>({
    tempo: 110,
    timeSignature: [4, 4],
    tracks: { melody: true, bass: true, drums: true }
  });
  const [showMidiSettings, setShowMidiSettings] = useState(false);

  const workletNodeRef = useRef<AudioWorkletNode | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const playbackTimersRef = useRef<number[]>([]);

  useEffect(() => {
    setLibrary(getLibrary());
    setPresets(getPresets());
    return () => {
      playbackTimersRef.current.forEach(clearTimeout);
    };
  }, []);

  const initEngine = async () => {
    if (audioContext.state === 'suspended') {
        await audioContext.resume();
    }
    const success = await loadProcessor();
    if (success) {
      const node = createPluginNode();
      const analyser = audioContext.createAnalyser();
      node.connect(analyser);
      analyser.connect(audioContext.destination);
      workletNodeRef.current = node;
      analyserRef.current = analyser;
      setIsReady(true);
      drawVisualizer();
      return true;
    }
    return false;
  };

  const drawVisualizer = () => {
    if (!canvasRef.current || !analyserRef.current) return;
    const ctx = canvasRef.current.getContext('2d');
    if (!ctx) return;
    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);

    const render = () => {
      if (!analyserRef.current) return;
      analyserRef.current.getByteFrequencyData(dataArray);
      ctx.clearRect(0, 0, canvasRef.current!.width, canvasRef.current!.height);
      const themeColor = style === Style.WizardRock ? '#a855f7' : '#f97316';
      ctx.fillStyle = themeColor;

      const barWidth = (canvasRef.current!.width / bufferLength) * 2.5;
      let x = 0;
      for (let i = 0; i < bufferLength; i++) {
        const barHeight = (dataArray[i] / 255) * canvasRef.current!.height;
        ctx.fillRect(x, canvasRef.current!.height - barHeight, barWidth, barHeight);
        x += barWidth + 1;
      }
      requestAnimationFrame(render);
    };
    render();
  };

  const playComposition = (compToPlay?: Composition) => {
    const comp = compToPlay || activeComp;
    if (!comp || !workletNodeRef.current) return;

    // Stop current audio and clear timers
    playbackTimersRef.current.forEach(clearTimeout);
    playbackTimersRef.current = [];
    workletNodeRef.current.port.postMessage({ gain: 0 });

    setIsPlaying(true);
    const shruti = getRagaShruti(comp.raga);

    comp.vocalTimeline.forEach(entry => {
      // Schedule Start
      const startTimer = window.setTimeout(() => {
        workletNodeRef.current?.port.postMessage({
          freq: 440 * Math.pow(2, (entry.midi - 69) / 12),
          tonic: 440 * Math.pow(2, (60 - 69) / 12), 
          ragaShruti: shruti,
          phoneme: entry.phoneme,
          bhakti: comp.mood === Mood.Bhakti,
          gender: vocalParams.gender,
          gamak: vocalParams.ornamentation === "gamak",
          gain: 1.0
        });
      }, entry.time * 1000);
      playbackTimersRef.current.push(startTimer);

      // Schedule End (Small gap between notes helps phrasing)
      const endTimer = window.setTimeout(() => {
        workletNodeRef.current?.port.postMessage({ gain: 0 });
      }, (entry.time + entry.duration - 0.01) * 1000);
      playbackTimersRef.current.push(endTimer);
    });

    const finishTime = (comp.vocalTimeline[comp.vocalTimeline.length - 1]?.time || 0) + 
                       (comp.vocalTimeline[comp.vocalTimeline.length - 1]?.duration || 0);

    const finishTimer = window.setTimeout(() => {
      setIsPlaying(false);
    }, finishTime * 1000 + 500);
    playbackTimersRef.current.push(finishTimer);
  };

  const handleGenerate = async () => {
    if (!isReady) {
      const ok = await initEngine();
      if (!ok) return;
    }

    setIsGenerating(true);
    try {
      const comp = await generateComposition(raga, style, mood, 110, lyricsSeed);
      setActiveComp(comp);
      setExportOptions(prev => ({ ...prev, tempo: comp.bpm }));
      playComposition(comp);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className={`min-h-screen p-4 md:p-8 transition-colors duration-700 ${style === Style.WizardRock ? 'bg-indigo-950' : 'bg-stone-950'}`}>
      <header className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h1 className="text-4xl font-bold font-outfit text-white tracking-tight flex items-center gap-2">
            <span className={style === Style.WizardRock ? 'text-purple-400' : 'text-orange-400'}>RagaMidi</span>
            <span className="text-sm font-normal bg-white/10 px-2 py-0.5 rounded uppercase tracking-widest text-white/60">Neural v2.5</span>
          </h1>
          <p className="text-white/40 text-sm mt-1">AI-Powered Indian Classical Vocal & Sitar Synthesis</p>
        </div>
        {!isReady && (
          <button 
            onClick={initEngine}
            className="px-6 py-3 bg-white text-black font-bold rounded-full hover:bg-white/90 transition-all flex items-center gap-2 glow-orange"
          >
            Connect Sound Engine
          </button>
        )}
      </header>

      <main className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-4 space-y-6">
          <section className="glass-panel p-6 rounded-3xl glow-orange shadow-2xl">
            <h2 className="text-lg font-semibold mb-4 text-white/90 flex items-center gap-2">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
              Composition Settings
            </h2>
            <div className="space-y-4">
              <div>
                <label className="text-xs uppercase tracking-widest text-white/40 mb-1 block font-bold">Raga Selection</label>
                <select 
                  value={raga} 
                  onChange={(e) => setRaga(e.target.value as Raga)}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-orange-500/50"
                >
                  {Object.values(Raga).sort().map(r => <option key={r} value={r} className="bg-stone-900">{r}</option>)}
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-xs uppercase tracking-widest text-white/40 mb-1 block font-bold">Style</label>
                  <select 
                    value={style} 
                    onChange={(e) => setStyle(e.target.value as Style)}
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-orange-500/50"
                  >
                    {Object.values(Style).map(s => <option key={s} value={s} className="bg-stone-900">{s}</option>)}
                  </select>
                </div>
                <div>
                  <label className="text-xs uppercase tracking-widest text-white/40 mb-1 block font-bold">Mood</label>
                  <select 
                    value={mood} 
                    onChange={(e) => setMood(e.target.value as Mood)}
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-orange-500/50"
                  >
                    {Object.values(Mood).map(m => <option key={m} value={m} className="bg-stone-900">{m}</option>)}
                  </select>
                </div>
              </div>
              <button 
                onClick={handleGenerate}
                disabled={isGenerating}
                className="w-full py-4 bg-orange-600 hover:bg-orange-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold rounded-2xl transition-all shadow-xl shadow-orange-950/40"
              >
                {isGenerating ? "Casting Neural Spell..." : "Generate & Sing"}
              </button>
            </div>
          </section>

          <section className="glass-panel p-6 rounded-3xl">
            <h2 className="text-lg font-semibold mb-4 text-white/90">Vocalist Configuration</h2>
            <div className="space-y-4">
              <div className="flex gap-4">
                {['male', 'female'].map(g => (
                  <button 
                    key={g}
