                 </div>
                 <div className="space-y-2 max-h-32 overflow-y-auto custom-scrollbar">
                    {presets.map(p => (
                      <div key={p.id} onClick={() => setVocalParams(p.params)} className="p-2.5 bg-white/5 border border-white/5 rounded-xl flex justify-between items-center cursor-pointer hover:bg-white/10 transition-colors">
                        <span className="text-white text-[10px] font-medium">{p.name}</span>
                        <button onClick={(e) => { e.stopPropagation(); deletePreset(p.id); setPresets(getPresets()); }} className="text-red-500/50 hover:text-red-500 px-2 font-bold text-lg leading-none">×</button>
                      </div>
