                    <div className="flex gap-2">
                      <span className="px-3 py-1 bg-white/5 border border-white/10 rounded-full text-xs text-white/60 font-medium">Raag {activeComp.raga}</span>
                      <span className="px-3 py-1 bg-white/5 border border-white/10 rounded-full text-xs text-white/60 font-medium uppercase tracking-tighter">{activeComp.style} • {activeComp.mood}</span>
