                <div className="flex-1 bg-gradient-to-b from-white/[0.04] to-transparent rounded-[4rem] relative group border border-white/5 overflow-hidden flex items-center justify-center">
                  <canvas ref={canvasRef} width={800} height={500} className="w-full h-full object-cover" />

