                </div>

                <div className="mt-20 space-y-12 relative z-10 text-center pb-8">
                  <div className="space-y-6">
                    <p className="text-[12px] uppercase tracking-[0.8em] text-white/20 font-black mb-6">Real-time Lyrics</p>
                    <p className="text-6xl font-outfit text-white font-black italic leading-[1.1] px-12 tracking-tight drop-shadow-[0_20px_50px_rgba(0,0,0,0.8)]">
                      "{activeComp.lyrics}"
