              </>
            ) : (
              <div className="flex-1 flex flex-col items-center justify-center text-center space-y-20 py-20">
                <div className="relative scale-125">
                  <div className="w-80 h-80 border border-white/5 rounded-full flex items-center justify-center animate-[spin_50s_linear_infinite]"></div>
                  <div className="w-72 h-72 border-2 border-dashed border-white/10 absolute top-4 left-4 rounded-full flex items-center justify-center animate-[spin_25s_linear_infinite_reverse]"></div>
                  <div className="absolute inset-0 flex items-center justify-center">
                    <div className="w-48 h-48 bg-white/[0.03] rounded-full flex items-center justify-center backdrop-blur-[120px] border border-white/5 shadow-inner">
                      <svg className="w-24 h-24 text-white/10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={0.2} d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" /></svg>
                    </div>
