                    Select your Raga architecture and Mood profile to begin. Your track will be synthesized using real-time glottal pulse modeling and formant shaping.
                  </p>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Global Session Library */}
        <div className="lg:col-span-3 space-y-6">
          <section className="glass-panel p-10 rounded-[3rem] border-white/5 h-full flex flex-col min-h-[750px] shadow-2xl">
            <h4 className="text-[12px] font-black text-white/30 uppercase tracking-[0.6em] mb-12">Session History</h4>
            <div className="space-y-6 flex-1 overflow-y-auto custom-scrollbar pr-4">
              {library.map(comp => (
                <div key={comp.id} className="p-10 bg-white/5 rounded-[2.5rem] flex flex-col gap-6 group hover:bg-white/10 transition-all border border-transparent hover:border-white/10 relative shadow-2xl active:scale-[0.97]">
                  <div onClick={() => { setActiveComp(comp); playComposition(comp); }} className="cursor-pointer space-y-2">
                    <p className="text-white font-black text-xl group-hover:text-orange-500 transition-colors truncate tracking-tight">{comp.title}</p>
                    <div className="flex flex-wrap items-center gap-4 mt-6">
                       <span className="text-[11px] text-white/40 uppercase tracking-[0.3em] font-black bg-white/5 px-4 py-2 rounded-full border border-white/5">Raag {comp.raga}</span>
                       <span className="text-[11px] text-white/20 uppercase tracking-[0.3em] font-black">{new Date(comp.timestamp).toLocaleDateString()}</span>
                    </div>
                  </div>
                  <button onClick={() => { deleteFromLibrary(comp.id); setLibrary(getLibrary()); }} className="absolute top-10 right-10 opacity-0 group-hover:opacity-100 p-3 text-white/10 hover:text-red-500 transition-all scale-125">
                    <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                  </button>
                </div>
              ))}
              {library.length === 0 && (
                <div className="text-center py-32 space-y-8 opacity-10">
                  <p className="text-white text-[12px] uppercase tracking-[0.8em] font-black">Archive Empty</p>
                </div>
              )}
            </div>
            <div className="mt-12 pt-12 border-t border-white/5">
              <div className="bg-orange-600/5 p-10 rounded-[2.5rem] border border-orange-500/10 shadow-inner">
                <p className="text-[12px] text-orange-500 font-black uppercase tracking-[0.4em] mb-5">Neural Engine V3.0</p>
                <p className="text-[14px] text-white/30 leading-relaxed font-light italic">
                  Advanced Syllabic Synthesis utilizing cascaded formant filters tuned to traditional Vedic intervals for absolute melodic purity.
                </p>
              </div>
            </div>
          </section>
        </div>
      </main>

      <footer className="max-w-7xl mx-auto mt-32 pb-24 border-t border-white/5 pt-20 text-center">
         <div className="flex flex-wrap justify-center gap-20 mb-16 opacity-30">
            {['NEURAL PHRASING', 'GLOTTAL PULSE', 'FORMANT SHAPING', 'RAGA METADATA', 'MIDI STEMS'].map(t => (
              <span key={t} className="text-[11px] uppercase tracking-[0.8em] font-black text-white">{t}</span>
            ))}
         </div>
         <p className="text-[12px] text-white/10 uppercase tracking-[1em] font-medium">RagaMidi Professional Studio • Silicon Valley Research Labs • MMXXV</p>
      </footer>
