                  </p>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Global Session Library */}
        <div className="lg:col-span-3 space-y-6">
          <section className="glass-panel p-10 rounded-[3rem] border-white/5 h-full flex flex-col min-h-[750px] shadow-2xl">
