            </div>
            <div className="mt-12 pt-12 border-t border-white/5">
              <div className="bg-orange-600/5 p-10 rounded-[2.5rem] border border-orange-500/10 shadow-inner">
                <p className="text-[12px] text-orange-500 font-black uppercase tracking-[0.4em] mb-5">Neural Engine V3.0</p>
                <p className="text-[14px] text-white/30 leading-relaxed font-light italic">
                  Advanced Syllabic Synthesis utilizing cascaded formant filters tuned to traditional Vedic intervals for absolute melodic purity.
                </p>
              </div>
            </div>
          </section>
        </div>
      </main>

      <footer className="max-w-7xl mx-auto mt-32 pb-24 border-t border-white/5 pt-20 text-center">
         <div className="flex flex-wrap justify-center gap-20 mb-16 opacity-30">
            {['NEURAL PHRASING', 'GLOTTAL PULSE', 'FORMANT SHAPING', 'RAGA METADATA', 'MIDI STEMS'].map(t => (
              <span key={t} className="text-[11px] uppercase tracking-[0.8em] font-black text-white">{t}</span>
            ))}
         </div>
         <p className="text-[12px] text-white/10 uppercase tracking-[1em] font-medium">RagaMidi Professional Studio • Silicon Valley Research Labs • MMXXV</p>
      </footer>
    </div>
