export enum Style {
  Classical = "Classical",
  WizardRock = "WizardRock",
  Devotional = "Devotional",
  Bollywood = "Bollywood"
}

export enum Mood {
  Peaceful = "Peaceful",
  Epic = "Epic",
  Romantic = "Romantic",
  Sad = "Sad",
  Energetic = "Energetic",
  Bhakti = "Bhakti"
}

export enum Swara {
  S = "S",
  r = "r",
  R = "R",
  g = "g",
  G = "G",
  m = "m",
  M = "M",
  P = "P",
  d = "d",
  D = "D",
  n = "n",
  N = "N"
