export interface VocalTimelineEntry {
  time: number;
  midi: number;
  phoneme: string;
  emotion: string;
  duration: number;
}

export interface Composition {
  id: string;
  title: string;
  raga: Raga;
  style: Style;
  mood: Mood;
  bpm: number;
  melody: { midi: number; start: number; duration: number; velocity: number }[];
  bass: { midi: number; start: number; duration: number; velocity: number }[];
  drums: { midiNote: number; start: number; duration: number; velocity: number }[];
  vocalTimeline: VocalTimelineEntry[];
  lyrics: string;
  lyricsTranslation?: string;
  customScale?: number[];
  timestamp: number;
}

export interface VocalParams {
  vibrato: number;
  grit: number;
  ornamentation: "none" | "meend" | "gamak" | "taan";
  timbre: "kishore" | "rafi";
  gender: "male" | "female";
}

export interface VocalPreset {
  id: string;
  name: string;
  params: VocalParams;
}

import React, { useState, useEffect, useRef } from 'react';
import { Raga, Style, Mood, Composition, VocalParams, VocalPreset } from './types';
import { loadProcessor, createPluginNode, audioContext } from './audioContext';
import { generateComposition, generateLyrics } from './services/geminiService';
import { saveToLibrary, getLibrary, deleteFromLibrary, savePreset, getPresets, deletePreset } from './services/storageService';
import { exportMidiFile, MidiExportOptions } from './services/midiService';
import { getRagaShruti } from './constants';

export default function App() {
  const [activeComp, setActiveComp] = useState<Composition | null>(null);
  const [library, setLibrary] = useState<Composition[]>([]);
  const [presets, setPresets] = useState<VocalPreset[]>([]);
  const [raga, setRaga] = useState<Raga>(Raga.Shivaranjani); // Set Shivaranjani as default
  const [style, setStyle] = useState<Style>(Style.Classical);
  const [mood, setMood] = useState<Mood>(Mood.Sad); // Shivaranjani is traditionally a "Sad" or romantic raga
  const [lyricsSeed, setLyricsSeed] = useState("");
  const [vocalParams, setVocalParams] = useState<VocalParams>({
    vibrato: 0.5,
    grit: 0.1,
    ornamentation: "meend",
    timbre: "kishore",
    gender: "male"
  });
  const [newPresetName, setNewPresetName] = useState("");
  const [isPlaying, setIsPlaying] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isReady, setIsReady] = useState(false);
  const [playbackProgress, setPlaybackProgress] = useState(0);

  // MIDI Export Options
  const [exportOptions, setExportOptions] = useState<MidiExportOptions>({
    tempo: 110,
    timeSignature: [4, 4],
    tracks: { melody: true, bass: true, drums: true }
  });
  const [showMidiSettings, setShowMidiSettings] = useState(false);

  const workletNodeRef = useRef<AudioWorkletNode | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const playbackTimersRef = useRef<number[]>([]);
  const animationRef = useRef<number>(null);

  useEffect(() => {
    setLibrary(getLibrary());
    setPresets(getPresets());
    return () => {
      playbackTimersRef.current.forEach(clearTimeout);
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, []);

  const initEngine = async () => {
    if (audioContext.state === 'suspended') {
        await audioContext.resume();
    }
    const success = await loadProcessor();
    if (success) {
      const node = createPluginNode();
      const analyser = audioContext.createAnalyser();
      node.connect(analyser);
      analyser.connect(audioContext.destination);
      workletNodeRef.current = node;
      analyserRef.current = analyser;
      setIsReady(true);
      drawVisualizer();
      return true;
    }
    return false;
  };

  const drawVisualizer = () => {
    if (!canvasRef.current || !analyserRef.current) return;
    const ctx = canvasRef.current.getContext('2d');
    if (!ctx) return;
    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);

    const render = () => {
      if (!analyserRef.current) return;
      analyserRef.current.getByteFrequencyData(dataArray);
      ctx.clearRect(0, 0, canvasRef.current!.width, canvasRef.current!.height);

      const themeColor = style === Style.WizardRock ? '#a855f7' : '#f97316';

      const barWidth = (canvasRef.current!.width / bufferLength) * 2.5;
      let x = 0;
      for (let i = 0; i < bufferLength; i++) {
        const barHeight = (dataArray[i] / 255) * canvasRef.current!.height;

        const gradient = ctx.createLinearGradient(0, canvasRef.current!.height, 0, canvasRef.current!.height - barHeight);
        gradient.addColorStop(0, themeColor);
        gradient.addColorStop(0.5, themeColor + '88');
        gradient.addColorStop(1, '#ffffff');

        ctx.fillStyle = gradient;
        ctx.fillRect(x, canvasRef.current!.height - barHeight, barWidth, barHeight);
        x += barWidth + 1;
      }
      animationRef.current = requestAnimationFrame(render);
    };
    render();
  };

  const playComposition = (compToPlay?: Composition) => {
    const comp = compToPlay || activeComp;
    if (!comp || !workletNodeRef.current) return;

    playbackTimersRef.current.forEach(clearTimeout);
    playbackTimersRef.current = [];
    workletNodeRef.current.port.postMessage({ gain: 0 });
    setPlaybackProgress(0);

    setIsPlaying(true);
    const shruti = getRagaShruti(comp.raga);
    const startTime = Date.now();

    comp.vocalTimeline.forEach(entry => {
      const startTimer = window.setTimeout(() => {
        workletNodeRef.current?.port.postMessage({
          freq: 440 * Math.pow(2, (entry.midi - 69) / 12),
          tonic: 440 * Math.pow(2, (60 - 69) / 12), 
          ragaShruti: shruti,
          phoneme: entry.phoneme,
          bhakti: comp.mood === Mood.Bhakti,
          gender: vocalParams.gender,
          gamak: vocalParams.ornamentation === "gamak",
          gain: 1.0
        });
      }, entry.time * 1000);
      playbackTimersRef.current.push(startTimer);

      const endTimer = window.setTimeout(() => {
        workletNodeRef.current?.port.postMessage({ gain: 0 });
      }, (entry.time + entry.duration - 0.005) * 1000);
      playbackTimersRef.current.push(endTimer);
    });

    const lastEvent = comp.vocalTimeline[comp.vocalTimeline.length - 1];
    const totalDuration = (lastEvent?.time || 0) + (lastEvent?.duration || 0);

    const progressInterval = window.setInterval(() => {
      const elapsed = (Date.now() - startTime) / 1000;
      const progress = Math.min((elapsed / totalDuration) * 100, 100);
      setPlaybackProgress(progress);
      if (progress >= 100) clearInterval(progressInterval);
    }, 50);
    playbackTimersRef.current.push(progressInterval);

    const finishTimer = window.setTimeout(() => {
      setIsPlaying(false);
      setPlaybackProgress(0);
      workletNodeRef.current?.port.postMessage({ gain: 0 });
    }, totalDuration * 1000 + 1000);
    playbackTimersRef.current.push(finishTimer);
  };

  const handleGenerate = async () => {
    if (!isReady) {
      const ok = await initEngine();
      if (!ok) return;
    }

    setIsGenerating(true);
    try {
      const comp = await generateComposition(raga, style, mood, 110, lyricsSeed);
      setActiveComp(comp);
      setExportOptions(prev => ({ ...prev, tempo: comp.bpm }));
      playComposition(comp);
    } catch (err) {
      console.error("Generation failed:", err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleShuffleRaga = () => {
    const ragaValues = Object.values(Raga).filter(r => r !== Raga.Custom);
    const randomRaga = ragaValues[Math.floor(Math.random() * ragaValues.length)];
    setRaga(randomRaga);
  };

  const handleSavePreset = () => {
    if (!newPresetName.trim()) return;
    const preset: VocalPreset = {
      id: crypto.randomUUID(),
      name: newPresetName,
      params: { ...vocalParams }
    };
    savePreset(preset);
    setPresets(getPresets());
    setNewPresetName("");
  };

  const handleDeletePreset = (id: string) => {
    deletePreset(id);
    setPresets(getPresets());
  };

  return (
    <div className={`min-h-screen p-4 md:p-8 transition-all duration-1000 ${style === Style.WizardRock ? 'bg-[#120a2e]' : 'bg-[#060608]'}`}>
      <header className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center mb-12 gap-4">
        <div className="flex items-center gap-6">
          <div className="w-16 h-16 bg-gradient-to-br from-orange-500 to-orange-700 rounded-[1.25rem] flex items-center justify-center font-bold text-white text-4xl shadow-[0_15px_40px_-10px_rgba(234,88,12,0.5)]">R</div>
          <div>
            <h1 className="text-4xl font-bold font-outfit text-white tracking-tighter flex items-center gap-2">
              <span>RagaMidi</span>
              <span className="text-[10px] font-black bg-white/10 px-3 py-1 rounded-full uppercase tracking-widest text-white/40 border border-white/5">Studio V3</span>
            </h1>
            <p className="text-white/20 text-xs mt-1 font-semibold tracking-[0.2em] uppercase">Neural Syllabic Synth Engine</p>
          </div>
        </div>
        {!isReady ? (
          <button 
            onClick={initEngine}
            className="px-10 py-4 bg-white text-black font-black rounded-full hover:bg-white/90 transition-all shadow-[0_20px_40px_-15px_rgba(255,255,255,0.2)] active:scale-95 text-xs uppercase tracking-widest"
          >
            Connect Sound Engine
          </button>
        ) : (
          <div className="flex items-center gap-4 px-8 py-3 bg-white/5 rounded-full border border-white/10">
             <div className="w-2.5 h-2.5 bg-orange-500 rounded-full animate-pulse shadow-[0_0_15px_orange]"></div>
             <span className="text-[11px] font-black text-white/50 uppercase tracking-[0.3em]">Neural Feed Active</span>
          </div>
        )}
      </header>

      <main className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-3 space-y-6">
          <section className="glass-panel p-8 rounded-[2.5rem] border-white/5 shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-[11px] font-black uppercase tracking-[0.4em] text-white/20">Creative Console</h2>
              <button 
                onClick={handleShuffleRaga}
                className="p-2 text-white/20 hover:text-orange-500 transition-all active:rotate-180 duration-500"
                title="Shuffle Raga"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                </svg>
              </button>
            </div>
            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] uppercase tracking-widest text-white/30 block font-black">Raga Profile</label>
                <select 
                  value={raga} 
                  onChange={(e) => setRaga(e.target.value as Raga)}
                  className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white text-sm focus:outline-none focus:border-orange-500/50 appearance-none cursor-pointer hover:bg-white/10 transition-colors font-bold"
                >
                  {Object.values(Raga).sort().map(r => <option key={r} value={r} className="bg-[#0f0f12]">{r}</option>)}
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-widest text-white/30 block font-black">Style</label>
                  <select 
                    value={style} 
                    onChange={(e) => setStyle(e.target.value as Style)}
                    className="w-full bg-white/5 border border-white/10 rounded-2xl px-4 py-3.5 text-white text-[11px] focus:outline-none appearance-none font-bold"
                  >
                    {Object.values(Style).map(s => <option key={s} value={s} className="bg-[#0f0f12]">{s}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-widest text-white/30 block font-black">Mood</label>
                  <select 
                    value={mood} 
                    onChange={(e) => setMood(e.target.value as Mood)}
                    className="w-full bg-white/5 border border-white/10 rounded-2xl px-4 py-3.5 text-white text-[11px] focus:outline-none appearance-none font-bold"
                  >
                    {Object.values(Mood).map(m => <option key={m} value={m} className="bg-[#0f0f12]">{m}</option>)}
                  </select>
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] uppercase tracking-widest text-white/30 block font-black">Composition Prompt</label>
                <textarea 
                  value={lyricsSeed}
                  onChange={(e) => setLyricsSeed(e.target.value)}
                  placeholder="Describe the soul of your song..."
                  className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white text-xs h-40 focus:outline-none focus:border-orange-500/50 resize-none placeholder:text-white/10 font-medium leading-relaxed"
                />
              </div>
              <button 
                onClick={handleGenerate}
                disabled={isGenerating}
                className="w-full py-5 bg-orange-600 hover:bg-orange-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-black rounded-2xl transition-all shadow-[0_20px_40px_-15px_rgba(234,88,12,0.4)] active:scale-95 text-[11px] uppercase tracking-[0.3em]"
              >
                {isGenerating ? "Synthesizing Neural Stems..." : "Generate AI Masterpiece"}
              </button>
            </div>
          </section>

          <section className="glass-panel p-8 rounded-[2.5rem] border-white/5">
            <h2 className="text-[11px] font-black uppercase tracking-[0.4em] mb-8 text-white/20">Neural Formants</h2>
            <div className="space-y-6">
              <div className="flex gap-2 p-1 bg-white/5 rounded-2xl">
                {['male', 'female'].map(g => (
                  <button 
                    key={g}
                    onClick={() => setVocalParams({...vocalParams, gender: g as any})}
                    className={`flex-1 py-3.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${vocalParams.gender === g ? 'bg-white/10 text-white shadow-xl' : 'text-white/20 hover:text-white/40'}`}
                  >
                    {g}
                  </button>
                ))}
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[9px] uppercase tracking-[0.3em] text-white/30 font-black">Ornamentation</label>
                  <select 
                    value={vocalParams.ornamentation}
                    onChange={(e) => setVocalParams({...vocalParams, ornamentation: e.target.value as any})}
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-3 py-3 text-white text-[10px] focus:outline-none appearance-none"
                  >
                    <option value="none">None</option>
                    <option value="meend">Meend</option>
                    <option value="gamak">Gamak</option>
                    <option value="taan">Taan</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] uppercase tracking-[0.3em] text-white/30 font-black">Model Timbre</label>
                  <select 
                    value={vocalParams.timbre}
                    onChange={(e) => setVocalParams({...vocalParams, timbre: e.target.value as any})}
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-3 py-3 text-white text-[10px] focus:outline-none appearance-none"
                  >
                    <option value="kishore">Kishore</option>
                    <option value="rafi">Rafi</option>
                  </select>
                </div>
              </div>
              <div className="space-y-5">
                {['vibrato', 'grit'].map(p => (
                  <div key={p} className="space-y-3">
                    <div className="flex justify-between items-center px-1">
                      <label className="text-[9px] uppercase tracking-[0.4em] text-white/30 font-black">{p}</label>
                      <span className="text-[10px] text-white/60 font-mono">{(vocalParams as any)[p].toFixed(2)}</span>
                    </div>
                    <input 
                      type="range" min="0" max="1" step="0.01" 
                      value={(vocalParams as any)[p]}
                      onChange={(e) => setVocalParams({...vocalParams, [p]: parseFloat(e.target.value)})}
                      className="w-full accent-orange-600 h-1 bg-white/10 rounded-full appearance-none cursor-pointer"
                    />
                  </div>
                ))}
              </div>

              <div className="pt-6 border-t border-white/5 space-y-4">
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    value={newPresetName} 
                    onChange={(e) => setNewPresetName(e.target.value)}
                    placeholder="Preset Name..."
                    className="flex-1 bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white text-[10px] focus:outline-none"
                  />
                  <button 
                    onClick={handleSavePreset}
                    className="px-4 bg-orange-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all"
                  >
                    Save
                  </button>
                </div>
                <div className="space-y-2 max-h-40 overflow-y-auto custom-scrollbar">
                  {presets.map(p => (
                    <div key={p.id} className="flex items-center justify-between p-3 bg-white/5 rounded-xl border border-white/5 group hover:bg-white/10 transition-all">
                      <button 
                        onClick={() => setVocalParams(p.params)}
                        className="flex-1 text-left text-[10px] text-white/50 font-bold tracking-wider hover:text-white transition-colors"
                      >
                        {p.name}
                      </button>
                      <button 
                        onClick={() => handleDeletePreset(p.id)}
                        className="text-white/10 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"
                      >
                        <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </section>
        </div>

        <div className="lg:col-span-6 space-y-6">
          <div className="glass-panel rounded-[4rem] p-12 min-h-[750px] flex flex-col relative group overflow-hidden border-white/10 shadow-[0_60px_120px_-30px_rgba(0,0,0,0.6)]">
            {activeComp ? (
              <>
                <div className="flex justify-between items-start mb-16 z-10">
                  <div className="space-y-4">
                    <h3 className="text-7xl font-black font-outfit text-white tracking-tighter leading-[0.9]">{activeComp.title}</h3>
                    <div className="flex gap-4">
                      <div className="px-6 py-2.5 bg-orange-600/10 border border-orange-500/20 rounded-full flex items-center gap-3">
                        <span className="w-2.5 h-2.5 bg-orange-500 rounded-full animate-pulse shadow-[0_0_15px_orange]"></span>
                        <span className="text-[12px] font-black text-orange-500 uppercase tracking-[0.3em]">Raag {activeComp.raga}</span>
                      </div>
                      <div className="px-6 py-2.5 bg-white/5 border border-white/10 rounded-full">
                        <span className="text-[12px] font-black text-white/40 uppercase tracking-[0.3em]">{activeComp.style}</span>
                      </div>
                    </div>
                  </div>
                  <div className="flex gap-5">
                    <button onClick={() => { saveToLibrary(activeComp); setLibrary(getLibrary()); }} className="w-20 h-20 bg-white/5 border border-white/10 rounded-full flex items-center justify-center text-white/20 hover:text-white transition-all hover:bg-white/10 hover:border-white/20 active:scale-90" title="Archive Session">
                      <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                    </button>
                    <button onClick={() => setShowMidiSettings(!showMidiSettings)} className="px-10 h-20 bg-white text-black font-black text-[12px] uppercase tracking-[0.3em] rounded-full hover:bg-white/90 transition-all flex items-center gap-4 active:scale-95 shadow-3xl">
                      <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                      MIDI Stems
                    </button>
                  </div>
                </div>

                {showMidiSettings && (
                  <div className="absolute right-12 top-44 z-30 w-[22rem] p-10 glass-panel rounded-[3rem] shadow-[0_80px_120px_-30px_rgba(0,0,0,1)] border-orange-500/40 animate-in fade-in zoom-in duration-300 backdrop-blur-[64px]">
                    <h4 className="text-[11px] font-black text-white/30 uppercase tracking-[0.5em] mb-10 text-center">Export Configuration</h4>
                    <div className="space-y-8">
                      <div className="grid grid-cols-2 gap-6">
                        <div className="space-y-3">
                          <label className="text-[10px] text-white/40 uppercase font-black tracking-widest">Master BPM</label>
                          <input type="number" value={exportOptions.tempo} onChange={e => setExportOptions({...exportOptions, tempo: parseInt(e.target.value)})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-5 text-white text-base font-mono focus:outline-none focus:border-orange-500/40"/>
                        </div>
                        <div className="space-y-3">
