import { GoogleGenAI, Type } from "@google/genai";
import { Raga, Style, Mood, Composition } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const compositionSchema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING },
    melody: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midi: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        },
        required: ["midi", "start", "duration", "velocity"]
      }
    },
    bass: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midi: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        }
      }
    },
    drums: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midiNote: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        }
      }
    },
    vocalTimeline: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          time: { type: Type.NUMBER },
          midi: { type: Type.NUMBER },
          phoneme: { type: Type.STRING },
          emotion: { type: Type.STRING },
          duration: { type: Type.NUMBER }
        },
        required: ["time", "midi", "phoneme", "duration"]
      }
    },
    lyrics: { type: Type.STRING },
    lyricsTranslation: { type: Type.STRING }
  },
  required: ["title", "melody", "vocalTimeline", "lyrics", "lyricsTranslation"]
};

export async function generateComposition(
  raga: Raga,
  style: Style,
  mood: Mood,
  bpm: number,
  lyricsSeed: string
): Promise<Composition> {
  const prompt = `
    Role: Master AI Music Composer & Raga Theoretician.
    Task: Generate a FULL 3-MINUTE LONG song composition. 

    COMPOSITION SCALE:
    - Duration: Exactly ~180 seconds (3:00 minutes).
    - Structure: Full arrangement including Intro (10s), Verse 1 (30s), Chorus (20s), Verse 2 (30s), Bridge (20s), Final Chorus (30s), and Outro (20s).
    - Event Density: The vocalTimeline MUST contain a massive sequence (at least 150-200 events) to cover the full 3-minute span without large gaps.
    - BPM: ${bpm}

    MUSICAL RULES:
    1. Scalic Integrity: Every note in melody, bass, and vocalTimeline MUST strictly be from the ${raga} scale.
    2. Stylistic Fusion: Blend traditional Indian classical elements with ${style} aesthetics.
    3. Lyrics: Poetic, long-form lyrics in Transliterated Hindi/Urdu.
    4. Translation: Evocative English translation for the entire narrative.

    Parameters:
    - Raga: ${raga}
    - Mood: ${mood}
    - Context: ${lyricsSeed}

    JSON REQUIREMENTS:
    - Return a complete JSON object matching the schema.
    - Ensure 'time' and 'start' values increment logically up to 180.0 seconds.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: compositionSchema
    }
  });

  const data = JSON.parse(response.text);

  return {
    ...data,
    id: crypto.randomUUID(),
    raga,
    style,
    mood,
    bpm,
    timestamp: Date.now()
  };
}

export async function generateLyrics(raga: Raga, style: Style, mood: Mood): Promise<string> {
  const prompt = `Generate a poetic 4-line lyric for a full length song in Raag ${raga}. Style: ${style}, Mood: ${mood}. Output only the lyrics in Hindi/English transliteration.`;
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt
  });
  return response.text.trim();
}

