import { Composition } from "../types";

export interface MidiExportOptions {
  tempo?: number;
  timeSignature?: [number, number];
  tracks: {
    melody: boolean;
    vocal: boolean;
    bass: boolean;
    drums: boolean;
  };
}

/**
 * Standard MIDI VLQ (Variable Length Quantity) encoding
 */
function encodeVLQ(num: number): number[] {
  const bytes: number[] = [];
  let n = Math.floor(num);
  bytes.unshift(n & 0x7F);
  while (n > 127) {
    n >>= 7;
    bytes.unshift((n & 0x7F) | 0x80);
  }
  return bytes;
}

/**
 * Robust MIDI File Generation for RagaMidi
 */
export function exportMidiFile(comp: Composition, options: MidiExportOptions) {
  const PPQ = 480; 
  const bpm = options.tempo || comp.bpm || 110;
  const ticksPerSecond = (bpm / 60) * PPQ;

  const tracks: Uint8Array[] = [];

  // 1. CONDUCTOR TRACK
  const conductorEvents: { time: number; data: number[] }[] = [];
  const msPerBeat = Math.floor(60000000 / bpm);
  conductorEvents.push({
    time: 0,
    data: [0xFF, 0x51, 0x03, (msPerBeat >> 16) & 0xFF, (msPerBeat >> 8) & 0xFF, msPerBeat & 0xFF]
  });
  const [num, den] = options.timeSignature || [4, 4];
  conductorEvents.push({
    time: 0,
    data: [0xFF, 0x58, 0x04, num, Math.floor(Math.log2(den)), 24, 8]
  });
  tracks.push(serializeTrack(conductorEvents));

  // 2. MELODY TRACK (Channel 1)
  if (options.tracks.melody && comp.melody?.length) {
    const events: { time: number; data: number[] }[] = [];
    events.push({ time: 0, data: [0xC0, 104] }); // Sitar
    comp.melody.forEach(n => {
      events.push({ time: Math.floor(n.start * ticksPerSecond), data: [0x90, n.midi, n.velocity] });
      events.push({ time: Math.floor((n.start + n.duration) * ticksPerSecond), data: [0x80, n.midi, 0] });
    });
    tracks.push(serializeTrack(events));
  }

  // 3. VOCAL TRACK (Channel 2)
  if (options.tracks.vocal && comp.vocalTimeline?.length) {
    const events: { time: number; data: number[] }[] = [];
    events.push({ time: 0, data: [0xC1, 54] }); // Voice
    comp.vocalTimeline.forEach(v => {
      events.push({ time: Math.floor(v.time * ticksPerSecond), data: [0x91, v.midi, 100] });
      events.push({ time: Math.floor((v.time + v.duration) * ticksPerSecond), data: [0x81, v.midi, 0] });
    });
    tracks.push(serializeTrack(events));
  }

  // 4. BASS TRACK (Channel 3)
  if (options.tracks.bass && comp.bass?.length) {
    const events: { time: number; data: number[] }[] = [];
    events.push({ time: 0, data: [0xC2, 32] }); // Bass
    comp.bass.forEach(n => {
      events.push({ time: Math.floor(n.start * ticksPerSecond), data: [0x92, n.midi, n.velocity] });
      events.push({ time: Math.floor((n.start + n.duration) * ticksPerSecond), data: [0x82, n.midi, 0] });
    });
    tracks.push(serializeTrack(events));
  }

  // 5. DRUMS TRACK (Channel 10)
  if (options.tracks.drums && comp.drums?.length) {
    const events: { time: number; data: number[] }[] = [];
    comp.drums.forEach(n => {
      events.push({ time: Math.floor(n.start * ticksPerSecond), data: [0x99, n.midiNote, n.velocity] });
      events.push({ time: Math.floor((n.start + n.duration) * ticksPerSecond), data: [0x89, n.midiNote, 0] });
    });
    tracks.push(serializeTrack(events));
  }

  function serializeTrack(events: { time: number; data: number[] }[]): Uint8Array {
    events.sort((a, b) => a.time - b.time);
    let trackBytes: number[] = [];
    let lastTick = 0;

    events.forEach(e => {
      const delta = Math.max(0, e.time - lastTick);
      trackBytes.push(...encodeVLQ(delta));
      trackBytes.push(...e.data);
      lastTick = e.time;
    });

    // Add End of Track Meta Event
    trackBytes.push(0x00, 0xFF, 0x2F, 0x00);

    const len = trackBytes.length;
    const chunk = new Uint8Array(8 + len);
    // MTrk
    chunk[0] = 0x4d; chunk[1] = 0x54; chunk[2] = 0x72; chunk[3] = 0x6b;
    // Length
    chunk[4] = (len >> 24) & 0xff;
    chunk[5] = (len >> 16) & 0xff;
    chunk[6] = (len >> 8) & 0xff;
    chunk[7] = len & 0xff;
    // Data
    chunk.set(trackBytes, 8);
    return chunk;
  }

  // MThd
  const header = new Uint8Array([
    0x4d, 0x54, 0x68, 0x64, // MThd
    0x00, 0x00, 0x00, 0x06, // Chunk Length
    0x00, 0x01,             // Format 1
    (tracks.length >> 8) & 0xFF, tracks.length & 0xFF, // Number of tracks
    (PPQ >> 8) & 0xFF, PPQ & 0xFF // Division (PPQ)
  ]);

  // Combine All Tracks
  const totalLength = header.length + tracks.reduce((sum, t) => sum + t.length, 0);
  const finalMidi = new Uint8Array(totalLength);
  finalMidi.set(header, 0);
  let currentOffset = header.length;
  tracks.forEach(t => {
    finalMidi.set(t, currentOffset);
    currentOffset += t.length;
  });

  // Safe browser download
  const blob = new Blob([finalMidi], { type: "audio/midi" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `${comp.title.replace(/\s+/g, '_')}.mid`;
  document.body.appendChild(a);
  a.click();
  setTimeout(() => {
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }, 100);
}

import { GoogleGenAI, Type } from "@google/genai";
import { Raga, Style, Mood, Composition } from "../types";

const compositionSchema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING },
    melody: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midi: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        },
        required: ["midi", "start", "duration", "velocity"]
      }
    },
    bass: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midi: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        }
      }
    },
    drums: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          midiNote: { type: Type.NUMBER },
          start: { type: Type.NUMBER },
          duration: { type: Type.NUMBER },
          velocity: { type: Type.NUMBER }
        }
      }
    },
    vocalTimeline: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          time: { type: Type.NUMBER },
          midi: { type: Type.NUMBER },
          phoneme: { type: Type.STRING },
          emotion: { type: Type.STRING },
          duration: { type: Type.NUMBER }
        },
        required: ["time", "midi", "phoneme", "duration"]
      }
    },
    lyrics: { type: Type.STRING },
    lyricsTranslation: { type: Type.STRING }
  },
  required: ["title", "melody", "vocalTimeline", "lyrics", "lyricsTranslation"]
};

export async function generateComposition(
  raga: Raga,
  style: Style,
  mood: Mood,
  bpm: number,
  lyricsSeed: string
): Promise<Composition> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    Role: Master AI Music Composer & Raga Theoretician.
    Task: Generate a 1-MINUTE LONG song composition. 

    COMPOSITION SCALE:
    - Duration: Exactly 60.0 seconds (1:00 minute).
    - Structure: Short form including Intro (5s), Main Theme (25s), Variation (20s), and Outro (10s).
    - Event Density: The vocalTimeline MUST contain a continuous sequence (at least 60-80 events) to cover the full 60-second span.
    - BPM: ${bpm}

    MUSICAL RULES:
    1. Scalic Integrity: Every note in melody, bass, and vocalTimeline MUST strictly be from the ${raga} scale.
    2. Stylistic Fusion: Blend traditional Indian classical elements with ${style} aesthetics.
    3. Lyrics: Poetic transliterated Hindi/Urdu.
    4. Translation: English translation for the narrative.

    Parameters:
    - Raga: ${raga}
    - Mood: ${mood}
    - Context: ${lyricsSeed}

    JSON REQUIREMENTS:
    - Return a complete JSON object matching the schema.
    - Ensure 'time' and 'start' values increment logically up to 60.0 seconds.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: compositionSchema
    }
  });

  const data = JSON.parse(response.text);

  return {
    ...data,
    id: crypto.randomUUID(),
    raga,
    style,
    mood,
    bpm,
    timestamp: Date.now()
  };
}

export async function generateLyrics(raga: Raga, style: Style, mood: Mood): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Generate a short poetic lyric for a Raag ${raga} composition. Style: ${style}, Mood: ${mood}. Output only the lyrics.`;
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt
  });
  return response.text.trim();
}

import React, { useState, useEffect, useRef } from 'react';
import { Raga, Style, Mood, Composition, VocalParams, VocalPreset, Swara } from './types';
import { loadProcessor, createPluginNode, audioContext } from './audioContext';
import { generateComposition, generateLyrics } from './services/geminiService';
import { saveToLibrary, getLibrary, deleteFromLibrary, savePreset, getPresets, deletePreset } from './services/storageService';
import { exportMidiFile, MidiExportOptions } from './services/midiService';
import { getRagaShruti, RAGA_SCALES } from './constants';

declare global {
  interface Window {
    aistudio: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

export default function App() {
  const [activeComp, setActiveComp] = useState<Composition | null>(null);
  const [library, setLibrary] = useState<Composition[]>([]);
  const [presets, setPresets] = useState<VocalPreset[]>([]);
  const [raga, setRaga] = useState<Raga>(Raga.Shivaranjani);
  const [style, setStyle] = useState<Style>(Style.Classical);
  const [mood, setMood] = useState<Mood>(Mood.Sad);
  const [lyricsSeed, setLyricsSeed] = useState("");
  const [vocalParams, setVocalParams] = useState<VocalParams>({
    vibrato: 0.5,
    grit: 0.1,
    ornamentation: "meend",
    timbre: "kishore",
    gender: "male"
  });
  const [newPresetName, setNewPresetName] = useState("");
  const [isPlaying, setIsPlaying] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isReady, setIsReady] = useState(false);
  const [playbackProgress, setPlaybackProgress] = useState(0);
  const [hasApiKey, setHasApiKey] = useState<boolean | null>(null);
  const [genError, setGenError] = useState<string | null>(null);

  const [exportOptions, setExportOptions] = useState<MidiExportOptions>({
    tempo: 110,
    timeSignature: [4, 4],
    tracks: { melody: true, vocal: true, bass: true, drums: true }
  });
  const [showMidiSettings, setShowMidiSettings] = useState(false);

  const workletNodeRef = useRef<AudioWorkletNode | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const playbackTimersRef = useRef<number[]>([]);
  const animationRef = useRef<number>(null);

  useEffect(() => {
    checkApiKey();
    setLibrary(getLibrary());
    setPresets(getPresets());
    return () => {
      playbackTimersRef.current.forEach(clearTimeout);
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, []);

  const checkApiKey = async () => {
    const hasKey = await window.aistudio.hasSelectedApiKey();
    setHasApiKey(hasKey);
  };

  const handleOpenKeySelection = async () => {
    await window.aistudio.openSelectKey();
    setHasApiKey(true); // Proceed as per instructions, assuming success
  };

  const initEngine = async () => {
    if (audioContext.state === 'suspended') {
        await audioContext.resume();
    }
    const success = await loadProcessor();
    if (success) {
      const node = createPluginNode();
      const analyser = audioContext.createAnalyser();
      node.connect(analyser);
      analyser.connect(audioContext.destination);
      workletNodeRef.current = node;
      analyserRef.current = analyser;
      setIsReady(true);
      drawVisualizer();
      return true;
    }
    return false;
  };

  const drawVisualizer = () => {
    if (!canvasRef.current || !analyserRef.current) return;
    const ctx = canvasRef.current.getContext('2d');
    if (!ctx) return;
    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);

    const render = () => {
      if (!analyserRef.current) return;
      analyserRef.current.getByteFrequencyData(dataArray);
      ctx.clearRect(0, 0, canvasRef.current!.width, canvasRef.current!.height);

      const themeColor = style === Style.WizardRock ? '#a855f7' : '#f97316';

      const barWidth = (canvasRef.current!.width / bufferLength) * 2.5;
      let x = 0;
      for (let i = 0; i < bufferLength; i++) {
        const barHeight = (dataArray[i] / 255) * canvasRef.current!.height;

        const gradient = ctx.createLinearGradient(0, canvasRef.current!.height, 0, canvasRef.current!.height - barHeight);
        gradient.addColorStop(0, themeColor);
        gradient.addColorStop(0.5, themeColor + '88');
        gradient.addColorStop(1, '#ffffff');

        ctx.fillStyle = gradient;
        ctx.fillRect(x, canvasRef.current!.height - barHeight, barWidth, barHeight);
        x += barWidth + 1;
      }
      animationRef.current = requestAnimationFrame(render);
    };
    render();
  };

  const playComposition = (compToPlay?: Composition) => {
    const comp = compToPlay || activeComp;
    if (!comp || !workletNodeRef.current) return;

    playbackTimersRef.current.forEach(clearTimeout);
    playbackTimersRef.current = [];
    workletNodeRef.current.port.postMessage({ gain: 0 });
    setPlaybackProgress(0);

    setIsPlaying(true);
    const shruti = getRagaShruti(comp.raga);
    const startTime = Date.now();

    comp.vocalTimeline.forEach(entry => {
      const startTimer = window.setTimeout(() => {
        workletNodeRef.current?.port.postMessage({
          freq: 440 * Math.pow(2, (entry.midi - 69) / 12),
          tonic: 440 * Math.pow(2, (60 - 69) / 12), 
          ragaShruti: shruti,
          phoneme: entry.phoneme,
          bhakti: comp.mood === Mood.Bhakti,
          gender: vocalParams.gender,
          gamak: vocalParams.ornamentation === "gamak",
          gain: 1.0
        });
      }, entry.time * 1000);
      playbackTimersRef.current.push(startTimer);

      const endTimer = window.setTimeout(() => {
        workletNodeRef.current?.port.postMessage({ gain: 0 });
      }, (entry.time + entry.duration - 0.005) * 1000);
      playbackTimersRef.current.push(endTimer);
    });

    const lastEvent = comp.vocalTimeline[comp.vocalTimeline.length - 1];
    const totalDuration = (lastEvent?.time || 0) + (lastEvent?.duration || 0);

    const progressInterval = window.setInterval(() => {
      const elapsed = (Date.now() - startTime) / 1000;
      const progress = Math.min((elapsed / totalDuration) * 100, 100);
      setPlaybackProgress(progress);
      if (progress >= 100) clearInterval(progressInterval);
    }, 50);
    playbackTimersRef.current.push(progressInterval);

    const finishTimer = window.setTimeout(() => {
      setIsPlaying(false);
      setPlaybackProgress(0);
      workletNodeRef.current?.port.postMessage({ gain: 0 });
    }, totalDuration * 1000 + 1000);
    playbackTimersRef.current.push(finishTimer);
  };

